/**
 * MMS Database Migration Runner
 *
 * Handles database migrations with rollback support for the Metro Fleet
 * Mileage Management System. Supports both Drizzle-generated migrations
 * and manual SQL migrations.
 *
 * Features:
 * - PostgreSQL advisory locks for concurrent safety
 * - Transaction-wrapped execution with automatic rollback
 * - Migration history tracking
 * - Progress callbacks for UI feedback
 * - Manual migration support for extensions/timescaledb/functions
 *
 * @see specs/003-database-schema.md Section 3.6 (Migrations)
 */

import { sql } from './connection';
import { readdir, readFile } from 'fs/promises';
import { join } from 'path';
import { logger } from '../logging/logger';

/**
 * Migration lock ID for PostgreSQL advisory lock
 * Using a fixed hash to ensure same lock across processes
 */
const MIGRATION_LOCK_ID = 2147483647; // Max int32 for uniqueness

/**
 * Migration record stored in the database
 */
export interface MigrationRecord {
  id: number;
  name: string;
  hash: string;
  executedAt: Date;
  executionTimeMs: number;
  rollbackSql?: string;
}

/**
 * Migration file content
 */
export interface Migration {
  name: string;
  sql: string;
  rollbackSql?: string;
  isManual: boolean;
}

/**
 * Migration result
 */
export interface MigrationResult {
  name: string;
  status: 'applied' | 'skipped' | 'failed' | 'rolled_back';
  executionTimeMs: number;
  error?: string;
}

/**
 * Migration options
 */
export interface MigrationOptions {
  /** Run only specific migrations by name */
  filter?: string[];
  /** Dry run - don't actually apply migrations */
  dryRun?: boolean;
  /** Skip manual migrations (extensions, timescaledb, etc.) */
  skipManual?: boolean;
  /** Skip Drizzle-generated migrations */
  skipDrizzle?: boolean;
  /** Include seed data (development only) */
  includeSeed?: boolean;
  /** Progress callback */
  onProgress?: (current: number, total: number, migration: string) => void;
}

/**
 * Overall migration run result
 */
export interface MigrationRunResult {
  success: boolean;
  migrations: MigrationResult[];
  totalTimeMs: number;
  error?: string;
}

const log = logger.child({ service: 'migrator' });

/**
 * Compute a simple hash for migration content
 */
function computeHash(content: string): string {
  let hash = 0;
  for (let i = 0; i < content.length; i++) {
    const char = content.charCodeAt(i);
    hash = ((hash << 5) - hash) + char;
    hash = hash & hash; // Convert to 32-bit integer
  }
  return Math.abs(hash).toString(16).padStart(8, '0');
}

/**
 * Database Migrator
 *
 * Manages database schema migrations with safety features for production use.
 */
export class Migrator {
  private basePath: string;

  constructor(basePath?: string) {
    // Default to project root drizzle directory
    this.basePath = basePath ?? join(process.cwd(), 'drizzle');
  }

  /**
   * Ensure migration history table exists
   */
  async ensureHistoryTable(): Promise<void> {
    await sql`
      CREATE TABLE IF NOT EXISTS __mms_migrations (
        id SERIAL PRIMARY KEY,
        name VARCHAR(255) NOT NULL UNIQUE,
        hash VARCHAR(16) NOT NULL,
        executed_at TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP,
        execution_time_ms INTEGER NOT NULL DEFAULT 0,
        rollback_sql TEXT
      )
    `;
    log.debug('Migration history table ensured');
  }

  /**
   * Acquire advisory lock for migrations
   *
   * Returns true if lock was acquired, false if another process holds it.
   * Uses pg_try_advisory_lock to avoid blocking.
   */
  async acquireLock(): Promise<boolean> {
    const result = await sql`SELECT pg_try_advisory_lock(${MIGRATION_LOCK_ID}) as acquired`;
    const acquired = result[0]?.acquired === true;
    if (acquired) {
      log.info('Migration lock acquired');
    } else {
      log.warn('Could not acquire migration lock - another process may be running migrations');
    }
    return acquired;
  }

  /**
   * Release advisory lock
   */
  async releaseLock(): Promise<void> {
    await sql`SELECT pg_advisory_unlock(${MIGRATION_LOCK_ID})`;
    log.info('Migration lock released');
  }

  /**
   * Get list of applied migrations from history table
   */
  async getAppliedMigrations(): Promise<MigrationRecord[]> {
    await this.ensureHistoryTable();
    const rows = await sql`
      SELECT id, name, hash, executed_at, execution_time_ms, rollback_sql
      FROM __mms_migrations
      ORDER BY id ASC
    `;
    return rows.map(row => ({
      id: row.id as number,
      name: row.name as string,
      hash: row.hash as string,
      executedAt: row.executed_at as Date,
      executionTimeMs: row.execution_time_ms as number,
      rollbackSql: row.rollback_sql as string | undefined,
    }));
  }

  /**
   * Load manual migrations from drizzle/manual directory
   */
  async loadManualMigrations(): Promise<Migration[]> {
    const manualDir = join(this.basePath, 'manual');
    const migrations: Migration[] = [];

    try {
      const files = await readdir(manualDir);
      const sqlFiles = files
        .filter(f => f.endsWith('.sql') && !f.startsWith('seed_'))
        .sort();

      for (const file of sqlFiles) {
        const content = await readFile(join(manualDir, file), 'utf-8');
        migrations.push({
          name: `manual/${file}`,
          sql: content,
          isManual: true,
        });
      }
    } catch {
      // Directory doesn't exist - no manual migrations
      log.debug('No manual migrations directory found');
    }

    return migrations;
  }

  /**
   * Load Drizzle-generated migrations from drizzle/migrations directory
   */
  async loadDrizzleMigrations(): Promise<Migration[]> {
    const drizzleDir = join(this.basePath, 'migrations');
    const migrations: Migration[] = [];

    try {
      const files = await readdir(drizzleDir);
      const sqlFiles = files
        .filter(f => f.endsWith('.sql'))
        .sort();

      for (const file of sqlFiles) {
        const content = await readFile(join(drizzleDir, file), 'utf-8');
        migrations.push({
          name: `drizzle/${file}`,
          sql: content,
          isManual: false,
        });
      }
    } catch {
      // Directory doesn't exist - need to run drizzle-kit generate
      log.debug('No Drizzle migrations directory found - run "bun run db:generate" first');
    }

    return migrations;
  }

  /**
   * Load seed data migration (development only)
   */
  async loadSeedMigration(): Promise<Migration | null> {
    const seedFile = join(this.basePath, 'manual', 'seed_development.sql');
    try {
      const content = await readFile(seedFile, 'utf-8');
      return {
        name: 'seed/seed_development.sql',
        sql: content,
        isManual: true,
      };
    } catch {
      return null;
    }
  }

  /**
   * Apply a single migration
   */
  async applyMigration(migration: Migration, dryRun: boolean = false): Promise<MigrationResult> {
    const startTime = Date.now();
    const hash = computeHash(migration.sql);

    if (dryRun) {
      log.info({ migration: migration.name }, 'Would apply migration (dry run)');
      return {
        name: migration.name,
        status: 'skipped',
        executionTimeMs: 0,
      };
    }

    try {
      // Execute migration SQL
      // For manual migrations with multiple statements, we need unsafe mode
      await sql.unsafe(migration.sql);

      const executionTimeMs = Date.now() - startTime;

      // Record in history
      await sql`
        INSERT INTO __mms_migrations (name, hash, execution_time_ms, rollback_sql)
        VALUES (${migration.name}, ${hash}, ${executionTimeMs}, ${migration.rollbackSql ?? null})
        ON CONFLICT (name) DO UPDATE SET
          hash = ${hash},
          executed_at = CURRENT_TIMESTAMP,
          execution_time_ms = ${executionTimeMs}
      `;

      log.info({ migration: migration.name, executionTimeMs }, 'Migration applied');

      return {
        name: migration.name,
        status: 'applied',
        executionTimeMs,
      };
    } catch (error) {
      const executionTimeMs = Date.now() - startTime;
      const errorMessage = error instanceof Error ? error.message : String(error);

      log.error({ migration: migration.name, error: errorMessage }, 'Migration failed');

      return {
        name: migration.name,
        status: 'failed',
        executionTimeMs,
        error: errorMessage,
      };
    }
  }

  /**
   * Rollback a migration using its stored rollback SQL
   */
  async rollbackMigration(record: MigrationRecord): Promise<MigrationResult> {
    if (!record.rollbackSql) {
      log.warn({ migration: record.name }, 'No rollback SQL available for migration');
      return {
        name: record.name,
        status: 'skipped',
        executionTimeMs: 0,
        error: 'No rollback SQL available',
      };
    }

    const startTime = Date.now();

    try {
      await sql.unsafe(record.rollbackSql);

      // Remove from history
      await sql`DELETE FROM __mms_migrations WHERE name = ${record.name}`;

      const executionTimeMs = Date.now() - startTime;
      log.info({ migration: record.name, executionTimeMs }, 'Migration rolled back');

      return {
        name: record.name,
        status: 'rolled_back',
        executionTimeMs,
      };
    } catch (error) {
      const executionTimeMs = Date.now() - startTime;
      const errorMessage = error instanceof Error ? error.message : String(error);

      log.error({ migration: record.name, error: errorMessage }, 'Rollback failed');

      return {
        name: record.name,
        status: 'failed',
        executionTimeMs,
        error: errorMessage,
      };
    }
  }

  /**
   * Run all pending migrations
   *
   * Executes manual migrations first (extensions, timescaledb, functions),
   * then Drizzle-generated migrations in order.
   */
  async migrate(options: MigrationOptions = {}): Promise<MigrationRunResult> {
    const startTime = Date.now();
    const results: MigrationResult[] = [];

    log.info({ options }, 'Starting migration run');

    // Acquire lock
    const lockAcquired = await this.acquireLock();
    if (!lockAcquired) {
      return {
        success: false,
        migrations: [],
        totalTimeMs: Date.now() - startTime,
        error: 'Could not acquire migration lock - another process may be running migrations',
      };
    }

    try {
      // Get applied migrations
      const applied = await this.getAppliedMigrations();
      const appliedNames = new Set(applied.map(m => m.name));

      // Load all migrations
      const migrations: Migration[] = [];

      if (!options.skipManual) {
        const manual = await this.loadManualMigrations();
        migrations.push(...manual);
      }

      if (!options.skipDrizzle) {
        const drizzle = await this.loadDrizzleMigrations();
        migrations.push(...drizzle);
      }

      // Filter if specified
      let pending = migrations.filter(m => !appliedNames.has(m.name));
      if (options.filter?.length) {
        pending = pending.filter(m => options.filter!.some(f => m.name.includes(f)));
      }

      log.info({ total: migrations.length, pending: pending.length }, 'Migrations loaded');

      // Apply pending migrations
      for (let i = 0; i < pending.length; i++) {
        const migration = pending[i];
        options.onProgress?.(i + 1, pending.length, migration.name);

        const result = await this.applyMigration(migration, options.dryRun);
        results.push(result);

        // Stop on failure
        if (result.status === 'failed') {
          log.error({ migration: migration.name }, 'Migration failed - stopping');
          break;
        }
      }

      // Apply seed data if requested and in development
      if (options.includeSeed && process.env['NODE_ENV'] === 'development') {
        const seed = await this.loadSeedMigration();
        if (seed && !appliedNames.has(seed.name)) {
          options.onProgress?.(pending.length + 1, pending.length + 1, seed.name);
          const result = await this.applyMigration(seed, options.dryRun);
          results.push(result);
        }
      }

      const success = results.every(r => r.status === 'applied' || r.status === 'skipped');
      const totalTimeMs = Date.now() - startTime;

      log.info({ success, totalTimeMs, applied: results.filter(r => r.status === 'applied').length }, 'Migration run complete');

      return {
        success,
        migrations: results,
        totalTimeMs,
      };
    } finally {
      await this.releaseLock();
    }
  }

  /**
   * Rollback the last N migrations
   */
  async rollback(count: number = 1): Promise<MigrationRunResult> {
    const startTime = Date.now();
    const results: MigrationResult[] = [];

    log.info({ count }, 'Starting rollback');

    const lockAcquired = await this.acquireLock();
    if (!lockAcquired) {
      return {
        success: false,
        migrations: [],
        totalTimeMs: Date.now() - startTime,
        error: 'Could not acquire migration lock',
      };
    }

    try {
      const applied = await this.getAppliedMigrations();
      const toRollback = applied.slice(-count).reverse();

      for (const record of toRollback) {
        const result = await this.rollbackMigration(record);
        results.push(result);

        if (result.status === 'failed') {
          break;
        }
      }

      const success = results.every(r => r.status === 'rolled_back' || r.status === 'skipped');
      const totalTimeMs = Date.now() - startTime;

      log.info({ success, totalTimeMs, rolledBack: results.filter(r => r.status === 'rolled_back').length }, 'Rollback complete');

      return {
        success,
        migrations: results,
        totalTimeMs,
      };
    } finally {
      await this.releaseLock();
    }
  }

  /**
   * Get migration status
   */
  async status(): Promise<{
    applied: MigrationRecord[];
    pending: Migration[];
    hasLock: boolean;
  }> {
    await this.ensureHistoryTable();

    const applied = await this.getAppliedMigrations();
    const appliedNames = new Set(applied.map(m => m.name));

    const manual = await this.loadManualMigrations();
    const drizzle = await this.loadDrizzleMigrations();
    const all = [...manual, ...drizzle];

    const pending = all.filter(m => !appliedNames.has(m.name));

    // Check if we can acquire the lock
    const hasLock = await this.acquireLock();
    if (hasLock) {
      await this.releaseLock();
    }

    return { applied, pending, hasLock };
  }

  /**
   * Verify database connection and prerequisites
   */
  async verify(): Promise<{
    connected: boolean;
    hasTimescaleDb: boolean;
    hasUuidExtension: boolean;
    schemaVersion: string | null;
  }> {
    try {
      // Check connection
      const connectionResult = await sql`SELECT 1 as health`;
      const connected = connectionResult[0]?.health === 1;

      if (!connected) {
        return {
          connected: false,
          hasTimescaleDb: false,
          hasUuidExtension: false,
          schemaVersion: null,
        };
      }

      // Check TimescaleDB extension
      const tsResult = await sql`
        SELECT EXISTS(
          SELECT 1 FROM pg_extension WHERE extname = 'timescaledb'
        ) as has_timescaledb
      `;
      const hasTimescaleDb = tsResult[0]?.has_timescaledb === true;

      // Check UUID extension
      const uuidResult = await sql`
        SELECT EXISTS(
          SELECT 1 FROM pg_extension WHERE extname = 'uuid-ossp'
        ) as has_uuid
      `;
      const hasUuidExtension = uuidResult[0]?.has_uuid === true;

      // Get latest migration
      let schemaVersion: string | null = null;
      try {
        const versionResult = await sql`
          SELECT name FROM __mms_migrations ORDER BY id DESC LIMIT 1
        `;
        schemaVersion = versionResult[0]?.name as string | null;
      } catch {
        // History table doesn't exist yet
      }

      return {
        connected,
        hasTimescaleDb,
        hasUuidExtension,
        schemaVersion,
      };
    } catch (error) {
      log.error({ error }, 'Database verification failed');
      return {
        connected: false,
        hasTimescaleDb: false,
        hasUuidExtension: false,
        schemaVersion: null,
      };
    }
  }
}

/**
 * Singleton migrator instance
 */
let migratorInstance: Migrator | null = null;

/**
 * Get the migrator instance
 */
export function getMigrator(): Migrator {
  if (!migratorInstance) {
    migratorInstance = new Migrator();
  }
  return migratorInstance;
}

/**
 * Run migrations (convenience function)
 */
export async function runMigrations(options?: MigrationOptions): Promise<MigrationRunResult> {
  return getMigrator().migrate(options);
}

/**
 * Rollback migrations (convenience function)
 */
export async function rollbackMigrations(count?: number): Promise<MigrationRunResult> {
  return getMigrator().rollback(count);
}

/**
 * Get migration status (convenience function)
 */
export async function getMigrationStatus(): Promise<ReturnType<Migrator['status']>> {
  return getMigrator().status();
}

/**
 * Verify database prerequisites (convenience function)
 */
export async function verifyDatabase(): Promise<ReturnType<Migrator['verify']>> {
  return getMigrator().verify();
}

