/**
 * HTTP middleware helper - measure request duration
 */
export function measureHttpRequest(
  method: string,
  path: string,
  status: number,
  durationMs: number
): void {
  const labels = { method, path, status: String(status) };
  httpRequestsTotal.inc(labels);
  httpRequestDuration.observe(labels, durationMs / 1000);
