/**
 * MMS Transaction Utilities
 *
 * Enhanced transaction helpers for reliable database operations.
 * Provides automatic rollback, nested transaction support, and tracing integration.
 *
 * @see specs/004-domain-services.md
 */

import { db, type Transaction, type Database } from '../db/connection';
import { withSpan, addSpanEvent, MmsAttributes, SpanKind } from '../tracing';
import { DatabaseError, TimeoutError } from '../errors';
import { logger } from '../logging/logger';

/**
 * Transaction options for controlling behavior
 */
export interface TransactionOptions {
  /** Maximum time to wait for transaction completion (ms) */
  timeoutMs?: number;
  /** Isolation level for the transaction */
  isolationLevel?: 'read_uncommitted' | 'read_committed' | 'repeatable_read' | 'serializable';
  /** Whether to trace the transaction */
  traceEnabled?: boolean;
  /** Custom operation name for tracing */
  operationName?: string;
}

const DEFAULT_OPTIONS: Required<TransactionOptions> = {
  timeoutMs: 30000, // 30 seconds
  isolationLevel: 'read_committed',
  traceEnabled: true,
  operationName: 'transaction',
};

/**
 * Transaction result with metadata
 */
export interface TransactionResult<T> {
  data: T;
  durationMs: number;
  rowsAffected?: number;
}

/**
 * Execute a function within a traced database transaction
 *
 * Features:
 * - Automatic commit on success
 * - Automatic rollback on error
 * - Timeout protection
 * - OpenTelemetry tracing integration
 * - Structured logging
 *
 * @example
 * ```typescript
 * const result = await tracedTransaction(
 *   async (tx) => {
 *     await tx.insert(trains).values(trainData);
 *     await tx.insert(pmSchedule).values(scheduleData);
 *     return { trainId: trainData.id };
 *   },
 *   { operationName: 'createTrainWithSchedule', timeoutMs: 10000 }
 * );
 * ```
 */
export async function tracedTransaction<T>(
  fn: (tx: Transaction) => Promise<T>,
  options?: TransactionOptions
): Promise<TransactionResult<T>> {
  const opts = { ...DEFAULT_OPTIONS, ...options };

  if (!opts.traceEnabled) {
    return executeTransaction(fn, opts);
  }

  return withSpan(
    `db.${opts.operationName}`,
    async (span) => {
      span.setAttribute(MmsAttributes.DB_OPERATION, 'transaction');
      span.setAttribute('db.system', 'postgresql');

      addSpanEvent('transaction.begin', {
        'db.transaction.isolation_level': opts.isolationLevel,
        'db.transaction.timeout_ms': opts.timeoutMs,
      });

      try {
        const result = await executeTransaction(fn, opts);

        addSpanEvent('transaction.commit', {
          'db.transaction.duration_ms': result.durationMs,
          ...(result.rowsAffected !== undefined && {
            'db.transaction.rows_affected': result.rowsAffected,
          }),
        });

        span.setAttribute(MmsAttributes.DB_ROWS_AFFECTED, result.rowsAffected ?? 0);

        return result;
      } catch (error) {
        addSpanEvent('transaction.rollback', {
          'db.transaction.error': error instanceof Error ? error.message : String(error),
        });
        throw error;
      }
    },
    { kind: SpanKind.CLIENT }
  );
}

/**
 * Execute transaction without tracing (internal)
 */
async function executeTransaction<T>(
  fn: (tx: Transaction) => Promise<T>,
  opts: Required<TransactionOptions>
): Promise<TransactionResult<T>> {
  const startTime = Date.now();

  // Create timeout promise
  const timeoutPromise = new Promise<never>((_, reject) => {
    setTimeout(() => {
      reject(
        new TimeoutError(`Transaction timed out after ${opts.timeoutMs}ms`, {
          operation: opts.operationName,
          timeoutMs: opts.timeoutMs,
        })
      );
    }, opts.timeoutMs);
  });

  try {
    // Race between transaction and timeout
    const data = await Promise.race([
      db.transaction(async (tx) => fn(tx)),
      timeoutPromise,
    ]);

    return {
      data,
      durationMs: Date.now() - startTime,
    };
  } catch (error) {
    const durationMs = Date.now() - startTime;

    // Enhance error with context
    if (error instanceof TimeoutError) {
      throw error;
    }

    if (error instanceof Error) {
      logger.error(
        {
          operation: opts.operationName,
          durationMs,
          error: error.message,
        },
        'Transaction failed'
      );

      throw new DatabaseError(`Transaction failed: ${error.message}`, {
        operation: opts.operationName,
        durationMs,
        originalError: error.name,
      });
    }

    throw error;
  }
}

/**
 * Simple transaction wrapper (non-traced)
 *
 * Use this for simple operations where tracing overhead is unnecessary.
 */
export async function simpleTransaction<T>(
  fn: (tx: Transaction) => Promise<T>
): Promise<T> {
  return db.transaction(async (tx) => fn(tx));
}

/**
 * Execute multiple operations in a single transaction with individual error handling
 *
 * Useful for batch operations where you want to collect errors but continue processing.
 * The transaction only commits if all operations succeed.
 *
 * @example
 * ```typescript
 * const results = await batchTransaction([
 *   (tx) => tx.insert(trains).values(train1),
 *   (tx) => tx.insert(trains).values(train2),
 *   (tx) => tx.insert(trains).values(train3),
 * ]);
 * // results contains success/error for each operation
 * ```
 */
export interface BatchResult<T> {
  index: number;
  success: boolean;
  data?: T;
  error?: Error;
}

export async function batchTransaction<T>(
  operations: Array<(tx: Transaction) => Promise<T>>,
  options?: TransactionOptions
): Promise<BatchResult<T>[]> {
  const opts = { ...DEFAULT_OPTIONS, ...options, operationName: options?.operationName ?? 'batch' };

  const result = await tracedTransaction<BatchResult<T>[]>(
    async (tx) => {
      const results: BatchResult<T>[] = [];

      for (let i = 0; i < operations.length; i++) {
        const operation = operations[i];
        if (!operation) continue;

        try {
          const data = await operation(tx);
          results.push({ index: i, success: true, data });
        } catch (error) {
          // In a strict batch, any error should fail the whole transaction
          // Re-throw to trigger rollback
          results.push({
            index: i,
            success: false,
            error: error instanceof Error ? error : new Error(String(error)),
          });
          throw error;
        }
      }

      return results;
    },
    opts
  );

  return result.data;
}

/**
 * Execute a read-only query (no transaction needed, but with tracing)
 */
export async function tracedQuery<T>(
  operationName: string,
  fn: (database: Database) => Promise<T>
): Promise<T> {
  return withSpan(
    `db.query.${operationName}`,
    async (span) => {
      span.setAttribute(MmsAttributes.DB_OPERATION, 'query');
      span.setAttribute('db.system', 'postgresql');

      const startTime = Date.now();
      const result = await fn(db);
      const durationMs = Date.now() - startTime;

      span.setAttribute('db.query.duration_ms', durationMs);

      return result;
    },
    { kind: SpanKind.CLIENT }
  );
}

/**
 * Re-export Transaction type for convenience
 */
export type { Transaction, Database };

