   264→ */
   265→export function validateTrain(train: Train): { valid: boolean; errors: ValidationError[] } {
   266→  const errors: ValidationError[] = [];
   267→
   268→  if (!isValidUuid(train.id)) {
   269→    errors.push({ field: 'id', message: 'Invalid UUID format' });
   270→  }
   271→  if (!train.trainNumber || train.trainNumber.length > 20) {
   272→    errors.push({ field: 'trainNumber', message: 'Train number must be 1-20 characters' });
   273→  }
   274→  if (!isValidUuid(train.fleetId)) {
   275→    errors.push({ field: 'fleetId', message: 'Invalid UUID format' });
   276→  }
   277→  if (!isValidMileage(train.currentMileageKm)) {
   278→    errors.push({ field: 'currentMileageKm', message: 'Mileage must be 0-10,000,000 km' });
   279→  }
   280→  if (!['FIT', 'RESTRICTED', 'GROUNDED'].includes(train.fitnessStatus)) {
   281→    errors.push({ field: 'fitnessStatus', message: 'Invalid fitness status' });
   282→  }
   283→  if (train.targetMileageKm !== undefined && !isValidMileage(train.targetMileageKm)) {
   284→    errors.push({ field: 'targetMileageKm', message: 'Mileage must be 0-10,000,000 km' });
   285→  }
   286→  if (train.displayColor !== undefined && !isValidHexColor(train.displayColor)) {
   287→    errors.push({ field: 'displayColor', message: 'Invalid hex color format' });
   288→  }
   289→
   290→  return { valid: errors.length === 0, errors };
   291→}
