  notes: 'string?',
});

const METER_EVENT_TYPES = ['RESET', 'REPLACEMENT', 'CALIBRATION', 'CORRECTION'] as const;

/**
 * Validate mileage reading
 */
export function validateMileageReading(
  data: MileageReading
): { valid: boolean; errors: ValidationError[] } {
  const errors: ValidationError[] = [];

  if (!isValidUuid(data.trainId)) {
    errors.push({ field: 'trainId', message: 'Invalid UUID format' });
  }
  if (!isValidDateString(data.readingDate)) {
    errors.push({ field: 'readingDate', message: 'Date must be in YYYY-MM-DD format' });
  }
  if (!isValidMileage(data.rawReadingKm)) {
    errors.push({ field: 'rawReadingKm', message: 'Mileage must be 0-10,000,000 km' });
  }
  if (data.adjustedReadingKm !== undefined && !isValidMileage(data.adjustedReadingKm)) {
    errors.push({ field: 'adjustedReadingKm', message: 'Mileage must be 0-10,000,000 km' });
  }
  if (data.validationStatus && !['VALID', 'ANOMALY', 'PENDING', 'REJECTED'].includes(data.validationStatus)) {
    errors.push({ field: 'validationStatus', message: 'Invalid validation status' });
  }

  return { valid: errors.length === 0, errors };
