/**
 * Validate meter event
 */
export function validateMeterEvent(data: MeterEvent): { valid: boolean; errors: ValidationError[] } {
  const errors: ValidationError[] = [];

  if (!isValidUuid(data.trainId)) {
    errors.push({ field: 'trainId', message: 'Invalid UUID format' });
  }
  if (!isValidDateString(data.eventDate)) {
    errors.push({ field: 'eventDate', message: 'Date must be in YYYY-MM-DD format' });
  }
  if (!METER_EVENT_TYPES.includes(data.eventType as (typeof METER_EVENT_TYPES)[number])) {
    errors.push({ field: 'eventType', message: 'Invalid event type' });
  }
  if (!isValidMileage(data.oldReadingKm)) {
    errors.push({ field: 'oldReadingKm', message: 'Mileage must be 0-10,000,000 km' });
  }
  if (!isValidMileage(data.newReadingKm)) {
    errors.push({ field: 'newReadingKm', message: 'Mileage must be 0-10,000,000 km' });
  }
  if (!Number.isInteger(data.adjustmentKm)) {
    errors.push({ field: 'adjustmentKm', message: 'Adjustment must be an integer' });
  }
  if (data.notes && data.notes.length > 500) {
    errors.push({ field: 'notes', message: 'Notes must be at most 500 characters' });
  }

  return { valid: errors.length === 0, errors };
}

