/** Parsed mileage CSV row with transformed values */
export interface ParsedMileageCsvRow {
  trainNumber: string;
  readingDate: string;
  odometerKm: number;
}

/** Parsed fleet roster CSV row with transformed values */
export interface ParsedFleetRosterCsvRow {
  trainNumber: string;
  fleetCode: string;
  currentMileageKm: number;
  commissioningDate?: string;
  fitnessStatus?: FitnessStatus;
}

/** Parsed PM history CSV row with transformed values */
export interface ParsedPmHistoryCsvRow {
  trainNumber: string;
  pmCode: string;
  completionDate: string;
  completionMileageKm?: number;
  workOrderId?: string;
}

/**
 * Parse and validate mileage CSV row
 */
export function parseMileageCsvRow(
  row: unknown
): { success: true; data: ParsedMileageCsvRow } | { success: false; errors: ValidationError[] } {
  const errors: ValidationError[] = [];

  if (!row || typeof row !== 'object') {
    return { success: false, errors: [{ field: 'row', message: 'Invalid row data' }] };
  }

  const r = row as Record<string, unknown>;
  const trainNumber = String(r['train_number'] || '');
  const readingDate = String(r['reading_date'] || '');
  const odometerKmStr = String(r['odometer_km'] || '');

  if (!trainNumber) {
    errors.push({ field: 'train_number', message: 'Train number required' });
  }
  if (!isValidDateString(readingDate)) {
    errors.push({ field: 'reading_date', message: 'Date must be in YYYY-MM-DD format' });
  }

  const odometerKm = parseInt(odometerKmStr, 10);
  if (isNaN(odometerKm) || !isValidMileage(odometerKm)) {
    errors.push({ field: 'odometer_km', message: 'Mileage must be 0-10,000,000 km' });
  }

  if (errors.length > 0) {
    return { success: false, errors };
  }

  return {
    success: true,
    data: {
      trainNumber,
      readingDate,
      odometerKm,
    },
  };
}

/**
 * Parse and validate fleet roster CSV row
 */
export function parseFleetRosterCsvRow(
  row: unknown
): { success: true; data: ParsedFleetRosterCsvRow } | { success: false; errors: ValidationError[] } {
  const errors: ValidationError[] = [];

  if (!row || typeof row !== 'object') {
    return { success: false, errors: [{ field: 'row', message: 'Invalid row data' }] };
  }

  const r = row as Record<string, unknown>;
  const trainNumber = String(r['train_number'] || '');
  const fleetCode = String(r['fleet_code'] || '');
  const currentMileageKmStr = String(r['current_mileage_km'] || '');
  const commissioningDate = r['commissioning_date'] ? String(r['commissioning_date']) : undefined;
  const fitnessStatusRaw = r['fitness_status'] ? String(r['fitness_status']) : undefined;

  if (!trainNumber) {
    errors.push({ field: 'train_number', message: 'Train number required' });
  }
  if (!fleetCode) {
    errors.push({ field: 'fleet_code', message: 'Fleet code required' });
  }

  const currentMileageKm = parseInt(currentMileageKmStr, 10);
  if (isNaN(currentMileageKm) || !isValidMileage(currentMileageKm)) {
    errors.push({ field: 'current_mileage_km', message: 'Mileage must be 0-10,000,000 km' });
  }

  if (commissioningDate && !isValidDateString(commissioningDate)) {
    errors.push({ field: 'commissioning_date', message: 'Date must be in YYYY-MM-DD format' });
  }

  let fitnessStatus: FitnessStatus | undefined;
  if (fitnessStatusRaw) {
    if (!['FIT', 'RESTRICTED', 'GROUNDED'].includes(fitnessStatusRaw)) {
      errors.push({ field: 'fitness_status', message: 'Invalid fitness status' });
    } else {
      fitnessStatus = fitnessStatusRaw as FitnessStatus;
    }
  }

  if (errors.length > 0) {
    return { success: false, errors };
  }

  return {
    success: true,
    data: {
      trainNumber,
      fleetCode,
      currentMileageKm,
      commissioningDate,
      fitnessStatus,
    },
  };
}

