// Scenario Schemas
// =============================================================================

export interface ScenarioCreate {
  name: string;
  description?: string;
  forkedFromBaselineId?: string;
  forkedFromScenarioId?: string;
}

export interface ScenarioDelta {
  deltaType: string;
  entityType: string;
  entityId: string;
  oldValues?: Record<string, unknown>;
  newValues: Record<string, unknown>;
  changeReason?: string;
}

export const scenarioCreateSchema = createSchema({
  name: 'string',
  description: 'string?',
  forkedFromBaselineId: 'string?',
  forkedFromScenarioId: 'string?',
});

export const scenarioDeltaSchema = createSchema({
  deltaType: 'string',
  entityType: 'string',
  entityId: 'string',
  oldValues: 'object?',
  newValues: 'object',
  changeReason: 'string?',
});

const DELTA_TYPES = ['PM_MOVE', 'PM_ADD', 'PM_REMOVE', 'CAPACITY_CHANGE', 'TRAIN_STATUS_CHANGE'] as const;

/**
 * Validate scenario create request
 */
export function validateScenarioCreate(
  data: ScenarioCreate
): { valid: boolean; errors: ValidationError[] } {
  const errors: ValidationError[] = [];

  if (!data.name || data.name.length > 100) {
    errors.push({ field: 'name', message: 'Name must be 1-100 characters' });
  }
  if (data.description && data.description.length > 500) {
    errors.push({ field: 'description', message: 'Description must be at most 500 characters' });
  }
  if (data.forkedFromBaselineId && !isValidUuid(data.forkedFromBaselineId)) {
    errors.push({ field: 'forkedFromBaselineId', message: 'Invalid UUID format' });
  }
  if (data.forkedFromScenarioId && !isValidUuid(data.forkedFromScenarioId)) {
    errors.push({ field: 'forkedFromScenarioId', message: 'Invalid UUID format' });
  }

  return { valid: errors.length === 0, errors };
}

/**
 * Validate scenario delta
 */
export function validateScenarioDelta(
  data: ScenarioDelta
): { valid: boolean; errors: ValidationError[] } {
  const errors: ValidationError[] = [];

  if (!DELTA_TYPES.includes(data.deltaType as (typeof DELTA_TYPES)[number])) {
    errors.push({ field: 'deltaType', message: 'Invalid delta type' });
  }
  if (!data.entityType) {
    errors.push({ field: 'entityType', message: 'Entity type required' });
  }
  if (!isValidUuid(data.entityId)) {
    errors.push({ field: 'entityId', message: 'Invalid UUID format' });
  }
  if (!data.newValues || typeof data.newValues !== 'object') {
    errors.push({ field: 'newValues', message: 'New values required' });
  }
  if (data.changeReason && data.changeReason.length > 500) {
    errors.push({ field: 'changeReason', message: 'Change reason must be at most 500 characters' });
  }

  return { valid: errors.length === 0, errors };
}

// =============================================================================
// Validation Helpers
// =============================================================================

/** Validation error structure */
export interface ValidationError {
  field: string;
  message: string;
}

/** Schema validation result */
export type SchemaResult<T> =
  | { success: true; data: T }
  | { success: false; errors: ValidationError[] };

/**
 * Parse and validate data using a schema
 * Compatible with previous Zod-based parseSchema API
 */
export function parseSchema<T>(
  schema: { parse: (data: unknown) => T; isValid?: (data: unknown) => boolean },
  data: unknown
): SchemaResult<T> {
  try {
    const parsed = schema.parse(data);
    return { success: true, data: parsed };
  } catch (err) {
    const message = err instanceof Error ? err.message : 'Validation failed';
    return {
      success: false,
      errors: [{ field: 'root', message }],
    };
  }
}

/**
 * Format validation errors for API response
 * Compatible with previous Zod-based formatZodErrors API
 */
export function formatValidationErrors(
  errors: ValidationError[]
): Array<{ field: string; message: string }> {
  return errors;
}

/**
 * Safe parse helper for compatibility with Zod's safeParse pattern
 */
export function safeParse<T>(
  schema: { parse: (data: unknown) => T },
  data: unknown
): { success: true; data: T } | { success: false; error: { errors: ValidationError[] } } {
  try {
    const parsed = schema.parse(data);
    return { success: true, data: parsed };
  } catch (err) {
    const message = err instanceof Error ? err.message : 'Validation failed';
    return {
      success: false,
      error: {
        errors: [{ field: 'root', message }],
      },
    };
  }
}

