    43→ */
    44→function createFailingFunction<T>(failCount: number, successValue: T, error?: Error) {
    45→  let attempts = 0;
    46→  return async () => {
    47→    attempts++;
    48→    if (attempts <= failCount) {
    49→      throw error ?? new Error(`Attempt ${attempts} failed`);
