    61→  };
    62→}
    63→
    64→/**
    65→ * Create a delayed function
    66→ */
    67→function createDelayedFunction<T>(value: T, delayMs: number) {
    68→  return async () => {
    69→    await new Promise((resolve) => setTimeout(resolve, delayMs));
    70→    return value;
