/**
 * MMS Resilience Utilities Unit Tests
 *
 * Tests for resilience patterns covering:
 * - Retry logic with exponential backoff and jitter
 * - Circuit breaker state transitions (CLOSED → OPEN → HALF_OPEN)
 * - Timeout behavior
 * - Error classification (isRetryable)
 * - Combined retry + circuit breaker (withResilience)
 *
 * These tests are CRITICAL as resilience patterns are foundational for
 * Maximo integration and external system reliability across the 12-year contract.
 *
 * @see src/lib/utils/resilience.ts
 * @see specs/007-integration.md - External system integration patterns
 */

import { describe, test, expect } from 'bun:test';
import {
  // Retry utilities
  withRetry,
  DEFAULT_RETRY_CONFIG,
  AGGRESSIVE_RETRY_CONFIG,
  QUICK_RETRY_CONFIG,
  EXTERNAL_SERVICE_RETRY_CONFIG,
  type RetryConfig,
  // Circuit breaker utilities
  CircuitBreaker,
  DEFAULT_CIRCUIT_BREAKER_CONFIG,
  type CircuitState,
  // Combined utilities
  withResilience,
  withTimeout,
} from './resilience';
import { TimeoutError, ExternalServiceError, ServiceUnavailableError } from '../errors';

// =============================================================================
// Test Helpers
// =============================================================================

/**
 * Create a function that fails N times then succeeds
 */
function createFailingFunction<T>(failCount: number, successValue: T, error?: Error) {
  let attempts = 0;
  return async () => {
    attempts++;
    if (attempts <= failCount) {
      throw error ?? new Error(`Attempt ${attempts} failed`);
    }
    return successValue;
  };
}

/**
 * Create a function that always fails
 */
function createAlwaysFailingFunction(error?: Error) {
  return async () => {
    throw error ?? new Error('Always fails');
  };
}

/**
 * Create a delayed function
 */
function createDelayedFunction<T>(value: T, delayMs: number) {
  return async () => {
    await new Promise((resolve) => setTimeout(resolve, delayMs));
    return value;
  };
}

// =============================================================================
// Retry Configuration Tests
// =============================================================================

describe('Retry Configuration', () => {
  describe('DEFAULT_RETRY_CONFIG', () => {
    test('should have sensible defaults', () => {
      expect(DEFAULT_RETRY_CONFIG.maxAttempts).toBe(3);
      expect(DEFAULT_RETRY_CONFIG.initialDelayMs).toBe(1000);
      expect(DEFAULT_RETRY_CONFIG.maxDelayMs).toBe(30000);
      expect(DEFAULT_RETRY_CONFIG.backoffMultiplier).toBe(2);
      expect(DEFAULT_RETRY_CONFIG.jitter).toBe(true);
      expect(DEFAULT_RETRY_CONFIG.isRetryable).toBeDefined();
    });
  });

  describe('AGGRESSIVE_RETRY_CONFIG', () => {
    test('should have more attempts than default', () => {
      expect(AGGRESSIVE_RETRY_CONFIG.maxAttempts).toBe(5);
      expect(AGGRESSIVE_RETRY_CONFIG.initialDelayMs).toBe(500);
      expect(AGGRESSIVE_RETRY_CONFIG.maxDelayMs).toBe(60000);
    });
  });

  describe('QUICK_RETRY_CONFIG', () => {
    test('should have shorter delays', () => {
      expect(QUICK_RETRY_CONFIG.maxAttempts).toBe(3);
      expect(QUICK_RETRY_CONFIG.initialDelayMs).toBe(100);
      expect(QUICK_RETRY_CONFIG.maxDelayMs).toBe(2000);
    });
  });

  describe('EXTERNAL_SERVICE_RETRY_CONFIG', () => {
    test('should be configured for external services', () => {
      expect(EXTERNAL_SERVICE_RETRY_CONFIG.maxAttempts).toBe(5);
      expect(EXTERNAL_SERVICE_RETRY_CONFIG.initialDelayMs).toBe(2000);
      expect(EXTERNAL_SERVICE_RETRY_CONFIG.maxDelayMs).toBe(60000);
    });

    test('should retry TimeoutError', () => {
      const isRetryable = EXTERNAL_SERVICE_RETRY_CONFIG.isRetryable!;
      expect(isRetryable(new TimeoutError('timeout'))).toBe(true);
    });

    test('should retry ExternalServiceError', () => {
      const isRetryable = EXTERNAL_SERVICE_RETRY_CONFIG.isRetryable!;
      expect(isRetryable(new ExternalServiceError('external service error'))).toBe(true);
    });

    test('should retry ServiceUnavailableError', () => {
      const isRetryable = EXTERNAL_SERVICE_RETRY_CONFIG.isRetryable!;
      expect(isRetryable(new ServiceUnavailableError('unavailable'))).toBe(true);
    });

    test('should retry network errors', () => {
      const isRetryable = EXTERNAL_SERVICE_RETRY_CONFIG.isRetryable!;
      expect(isRetryable(new Error('Network error'))).toBe(true);
      expect(isRetryable(new Error('ECONNREFUSED'))).toBe(true);
      expect(isRetryable(new Error('ECONNRESET'))).toBe(true);
      expect(isRetryable(new Error('socket hang up'))).toBe(true);
      expect(isRetryable(new Error('timeout occurred'))).toBe(true);
    });

    test('should not retry generic errors', () => {
      const isRetryable = EXTERNAL_SERVICE_RETRY_CONFIG.isRetryable!;
      expect(isRetryable(new Error('Something went wrong'))).toBe(false);
      expect(isRetryable(new Error('Invalid input'))).toBe(false);
    });
  });
});

// =============================================================================
// withRetry Tests
// =============================================================================

describe('withRetry', () => {
  describe('Successful execution', () => {
    test('should return result on first success', async () => {
      const fn = async () => 'success';
      const result = await withRetry(fn, { maxAttempts: 3, jitter: false });
      expect(result).toBe('success');
    });

    test('should return result after transient failures', async () => {
      const fn = createFailingFunction(2, 'success');
      const result = await withRetry(fn, {
        maxAttempts: 3,
        initialDelayMs: 10,
        jitter: false,
      });
      expect(result).toBe('success');
    });
  });

  describe('Failed execution', () => {
    test('should throw after max attempts exhausted', async () => {
      const fn = createAlwaysFailingFunction();

      await expect(
        withRetry(fn, {
          maxAttempts: 3,
          initialDelayMs: 10,
          jitter: false,
        })
      ).rejects.toThrow('Always fails');
    });

    test('should throw immediately if error is not retryable', async () => {
      const fn = createAlwaysFailingFunction(new Error('Not retryable'));
      const startTime = Date.now();

      await expect(
        withRetry(fn, {
          maxAttempts: 5,
          initialDelayMs: 1000,
          isRetryable: () => false,
        })
      ).rejects.toThrow('Not retryable');

      // Should fail fast without waiting for retries
      expect(Date.now() - startTime).toBeLessThan(500);
    });
  });

  describe('Exponential backoff', () => {
    test('should increase delay exponentially', async () => {
      const delays: number[] = [];
      const fn = createAlwaysFailingFunction();

      try {
        await withRetry(fn, {
          maxAttempts: 4,
          initialDelayMs: 100,
          maxDelayMs: 10000,
          backoffMultiplier: 2,
          jitter: false,
          onRetry: (_error, _attempt, delayMs) => {
            delays.push(delayMs);
          },
        });
      } catch {
        // Expected to fail
      }

      // Expected delays: 100, 200, 400 (3 retries after initial attempt)
      expect(delays).toHaveLength(3);
      expect(delays[0]).toBe(100);
      expect(delays[1]).toBe(200);
      expect(delays[2]).toBe(400);
    });

    test('should cap delay at maxDelayMs', async () => {
      const delays: number[] = [];
      const fn = createAlwaysFailingFunction();

      try {
        await withRetry(fn, {
          maxAttempts: 6,
          initialDelayMs: 100,
          maxDelayMs: 300,
          backoffMultiplier: 2,
          jitter: false,
          onRetry: (_error, _attempt, delayMs) => {
            delays.push(delayMs);
          },
        });
      } catch {
        // Expected to fail
      }

      // Expected delays: 100, 200, 300, 300, 300 (capped at maxDelayMs)
      expect(delays).toHaveLength(5);
      expect(delays[0]).toBe(100);
      expect(delays[1]).toBe(200);
      expect(delays[2]).toBe(300); // Capped
      expect(delays[3]).toBe(300); // Capped
      expect(delays[4]).toBe(300); // Capped
    });
  });

  describe('Jitter', () => {
    test('should add jitter when enabled', async () => {
      const delays: number[] = [];
      const fn = createAlwaysFailingFunction();

      try {
        await withRetry(fn, {
          maxAttempts: 5,
          initialDelayMs: 100,
          maxDelayMs: 10000,
          backoffMultiplier: 2,
          jitter: true,
          onRetry: (_error, _attempt, delayMs) => {
            delays.push(delayMs);
          },
        });
      } catch {
        // Expected to fail
      }

      // With jitter, delays should vary (±25%)
      // Base delays would be: 100, 200, 400, 800
      // With jitter: 75-125, 150-250, 300-500, 600-1000
      expect(delays).toHaveLength(4);

      // First delay should be in jitter range around 100
      expect(delays[0]).toBeGreaterThanOrEqual(75);
      expect(delays[0]).toBeLessThanOrEqual(125);
    });
  });

  describe('onRetry callback', () => {
    test('should invoke callback on each retry', async () => {
      const retries: Array<{ error: unknown; attempt: number; delayMs: number }> = [];
      const fn = createFailingFunction(2, 'success');

      await withRetry(fn, {
        maxAttempts: 3,
        initialDelayMs: 10,
        jitter: false,
        onRetry: (error, attempt, delayMs) => {
          retries.push({ error, attempt, delayMs });
        },
      });

      expect(retries).toHaveLength(2);
      expect(retries[0].attempt).toBe(1);
      expect(retries[1].attempt).toBe(2);
    });

    test('should not invoke callback on success', async () => {
      const retries: number[] = [];
      const fn = async () => 'success';

      await withRetry(fn, {
        maxAttempts: 3,
        onRetry: (_error, attempt) => {
          retries.push(attempt);
        },
      });

      expect(retries).toHaveLength(0);
    });
  });

  describe('isRetryable predicate', () => {
    test('should respect custom isRetryable function', async () => {
      let attempts = 0;
      const fn = async () => {
        attempts++;
        if (attempts === 1) throw new Error('retryable');
        if (attempts === 2) throw new Error('not-retryable');
        return 'success';
      };

      await expect(
        withRetry(fn, {
          maxAttempts: 5,
          initialDelayMs: 10,
          isRetryable: (error) => {
            return error instanceof Error && error.message === 'retryable';
          },
        })
      ).rejects.toThrow('not-retryable');

      expect(attempts).toBe(2);
    });

    test('should not retry 4xx client errors by default', async () => {
      const error = new Error('Bad Request') as Error & { statusCode: number };
      error.statusCode = 400;

      let attempts = 0;
      const fn = async () => {
        attempts++;
        throw error;
      };

      await expect(withRetry(fn, { maxAttempts: 3, initialDelayMs: 10 })).rejects.toThrow(
        'Bad Request'
      );

      expect(attempts).toBe(1); // Should not retry
    });

    test('should retry 408 timeout status code', async () => {
      const error = new Error('Request Timeout') as Error & { statusCode: number };
      error.statusCode = 408;

      let attempts = 0;
      const fn = async () => {
        attempts++;
        if (attempts < 3) throw error;
        return 'success';
      };

      const result = await withRetry(fn, { maxAttempts: 3, initialDelayMs: 10, jitter: false });
      expect(result).toBe('success');
      expect(attempts).toBe(3);
    });

    test('should retry 429 rate limit status code', async () => {
      const error = new Error('Too Many Requests') as Error & { statusCode: number };
      error.statusCode = 429;

      let attempts = 0;
      const fn = async () => {
        attempts++;
        if (attempts < 3) throw error;
        return 'success';
      };

      const result = await withRetry(fn, { maxAttempts: 3, initialDelayMs: 10, jitter: false });
      expect(result).toBe('success');
      expect(attempts).toBe(3);
    });

    test('should not retry BUS_ error codes', async () => {
      const error = new Error('Business rule violated') as Error & { code: string };
      error.code = 'BUS_001';

      let attempts = 0;
      const fn = async () => {
        attempts++;
        throw error;
      };

      await expect(withRetry(fn, { maxAttempts: 3, initialDelayMs: 10 })).rejects.toThrow(
        'Business rule violated'
      );

      expect(attempts).toBe(1); // Should not retry
    });

    test('should not retry AUTH_ error codes', async () => {
      const error = new Error('Authentication failed') as Error & { code: string };
      error.code = 'AUTH_001';

      let attempts = 0;
      const fn = async () => {
        attempts++;
        throw error;
      };

      await expect(withRetry(fn, { maxAttempts: 3, initialDelayMs: 10 })).rejects.toThrow(
        'Authentication failed'
      );

      expect(attempts).toBe(1); // Should not retry
    });
  });
});

// =============================================================================
// Circuit Breaker Configuration Tests
// =============================================================================

describe('Circuit Breaker Configuration', () => {
  describe('DEFAULT_CIRCUIT_BREAKER_CONFIG', () => {
    test('should have sensible defaults', () => {
      expect(DEFAULT_CIRCUIT_BREAKER_CONFIG.failureThreshold).toBe(5);
      expect(DEFAULT_CIRCUIT_BREAKER_CONFIG.successThreshold).toBe(3);
      expect(DEFAULT_CIRCUIT_BREAKER_CONFIG.resetTimeoutMs).toBe(30000);
      expect(DEFAULT_CIRCUIT_BREAKER_CONFIG.isFailure).toBeDefined();
    });
