// =============================================================================
// Circuit Breaker Tests
// =============================================================================

describe('CircuitBreaker', () => {
  describe('Initialization', () => {
    test('should initialize in CLOSED state', () => {
      const breaker = new CircuitBreaker();
      expect(breaker.getState()).toBe('CLOSED');
    });

    test('should accept custom configuration', () => {
      const breaker = new CircuitBreaker({
        failureThreshold: 3,
        successThreshold: 2,
        resetTimeoutMs: 10000,
      });

      const metrics = breaker.getMetrics();
      expect(metrics.state).toBe('CLOSED');
    });

    test('should accept custom name', () => {
      const breaker = new CircuitBreaker({}, 'maximo');
      expect(breaker.getState()).toBe('CLOSED');
    });
  });

  describe('CLOSED state', () => {
    test('should allow requests through', async () => {
      const breaker = new CircuitBreaker();
      const result = await breaker.execute(async () => 'success');
      expect(result).toBe('success');
    });

    test('should track successful requests', async () => {
      const breaker = new CircuitBreaker();
      await breaker.execute(async () => 'success');

      const metrics = breaker.getMetrics();
      expect(metrics.totalRequests).toBe(1);
      expect(metrics.totalSuccesses).toBe(1);
      expect(metrics.lastSuccessTime).not.toBeNull();
    });

    test('should reset failure count on success', async () => {
      const breaker = new CircuitBreaker({ failureThreshold: 5 });

      // Cause some failures
      for (let i = 0; i < 3; i++) {
        try {
          await breaker.execute(createAlwaysFailingFunction());
        } catch {
          // Expected
        }
      }

      // Success should reset failures
      await breaker.execute(async () => 'success');

      const metrics = breaker.getMetrics();
      expect(metrics.failures).toBe(0);
      expect(metrics.state).toBe('CLOSED');
    });
  });

  describe('State transitions: CLOSED → OPEN', () => {
    test('should open after failure threshold exceeded', async () => {
      const breaker = new CircuitBreaker({
        failureThreshold: 3,
        resetTimeoutMs: 10000,
      });

      const fn = createAlwaysFailingFunction();

      // Trigger failures
      for (let i = 0; i < 3; i++) {
        try {
          await breaker.execute(fn);
        } catch {
          // Expected
        }
      }

      expect(breaker.getState()).toBe('OPEN');
    });

    test('should call onStateChange callback', async () => {
      const stateChanges: Array<{ from: CircuitState; to: CircuitState }> = [];
      const breaker = new CircuitBreaker({
        failureThreshold: 2,
        onStateChange: (from, to) => {
          stateChanges.push({ from, to });
        },
      });

      // Trigger failures to open circuit
      for (let i = 0; i < 2; i++) {
        try {
          await breaker.execute(createAlwaysFailingFunction());
        } catch {
          // Expected
        }
      }

      expect(stateChanges).toHaveLength(1);
      expect(stateChanges[0]).toEqual({ from: 'CLOSED', to: 'OPEN' });
    });
  });

  describe('OPEN state', () => {
    test('should reject requests immediately', async () => {
      const breaker = new CircuitBreaker({
        failureThreshold: 1,
        resetTimeoutMs: 10000,
      });

      // Open the circuit
      try {
        await breaker.execute(createAlwaysFailingFunction());
      } catch {
        // Expected
      }

      expect(breaker.getState()).toBe('OPEN');

      // Should fail fast
      await expect(breaker.execute(async () => 'success')).rejects.toThrow(ServiceUnavailableError);
    });

    test('should throw ServiceUnavailableError with retryAfter', async () => {
      const breaker = new CircuitBreaker({
        failureThreshold: 1,
        resetTimeoutMs: 5000,
      });

      // Open the circuit
      try {
        await breaker.execute(createAlwaysFailingFunction());
      } catch {
        // Expected
      }

      try {
        await breaker.execute(async () => 'success');
      } catch (error) {
        expect(error).toBeInstanceOf(ServiceUnavailableError);
        // retryAfter is a direct property on ServiceUnavailableError
        expect((error as ServiceUnavailableError).retryAfter).toBe(5);
      }
    });

    test('should not count rejected requests as failures', async () => {
      const breaker = new CircuitBreaker({
        failureThreshold: 1,
        resetTimeoutMs: 10000,
      });

      // Open the circuit
      try {
        await breaker.execute(createAlwaysFailingFunction());
      } catch {
        // Expected
      }

      const metricsBefore = breaker.getMetrics();
      const failuresBefore = metricsBefore.totalFailures;

      // Try to execute (will be rejected)
      try {
        await breaker.execute(async () => 'success');
      } catch {
        // Expected
      }

      const metricsAfter = breaker.getMetrics();
      expect(metricsAfter.totalFailures).toBe(failuresBefore);
    });
  });

  describe('State transitions: OPEN → HALF_OPEN', () => {
    test('should transition after resetTimeout', async () => {
      const breaker = new CircuitBreaker({
        failureThreshold: 1,
        resetTimeoutMs: 50, // Very short for testing
      });

      // Open the circuit
      try {
        await breaker.execute(createAlwaysFailingFunction());
      } catch {
        // Expected
      }

      expect(breaker.getState()).toBe('OPEN');

      // Wait for reset timeout
      await new Promise((resolve) => setTimeout(resolve, 100));

      // Check state (should auto-transition on getState)
      expect(breaker.getState()).toBe('HALF_OPEN');
    });

    test('should allow one request through in HALF_OPEN', async () => {
      const breaker = new CircuitBreaker({
        failureThreshold: 1,
        resetTimeoutMs: 50,
        successThreshold: 1,
      });

      // Open the circuit
      try {
        await breaker.execute(createAlwaysFailingFunction());
      } catch {
        // Expected
      }

      // Wait for reset timeout
      await new Promise((resolve) => setTimeout(resolve, 100));

      // Should be able to execute
      const result = await breaker.execute(async () => 'recovered');
      expect(result).toBe('recovered');
    });
  });

  describe('HALF_OPEN state', () => {
    test('should close after success threshold reached', async () => {
      const breaker = new CircuitBreaker({
        failureThreshold: 1,
        successThreshold: 3,
        resetTimeoutMs: 50,
      });

      // Open the circuit
      try {
        await breaker.execute(createAlwaysFailingFunction());
      } catch {
        // Expected
      }

      // Wait for reset timeout
      await new Promise((resolve) => setTimeout(resolve, 100));

      expect(breaker.getState()).toBe('HALF_OPEN');

      // Successful executions
      for (let i = 0; i < 3; i++) {
        await breaker.execute(async () => 'success');
      }

      expect(breaker.getState()).toBe('CLOSED');
    });

    test('should reopen on any failure in HALF_OPEN', async () => {
      const breaker = new CircuitBreaker({
        failureThreshold: 1,
        successThreshold: 5,
        resetTimeoutMs: 50,
      });

      // Open the circuit
      try {
        await breaker.execute(createAlwaysFailingFunction());
      } catch {
        // Expected
      }

      // Wait for reset timeout
      await new Promise((resolve) => setTimeout(resolve, 100));

      expect(breaker.getState()).toBe('HALF_OPEN');

      // One success
      await breaker.execute(async () => 'success');

      // Then a failure
      try {
        await breaker.execute(createAlwaysFailingFunction());
      } catch {
        // Expected
      }

      expect(breaker.getState()).toBe('OPEN');
    });
  });

  describe('isFailure predicate', () => {
    test('should count critical errors as failures', async () => {
      const breaker = new CircuitBreaker({
        failureThreshold: 2,
        isFailure: (error) => {
          return error instanceof Error && error.message.includes('critical');
        },
      });

      // Critical errors should count
      for (let i = 0; i < 2; i++) {
        try {
          await breaker.execute(async () => {
            throw new Error('critical failure');
          });
        } catch {
          // Expected
        }
      }

      expect(breaker.getState()).toBe('OPEN');
    });

    test('should distinguish between critical and non-critical in same breaker', async () => {
      const breaker = new CircuitBreaker({
        failureThreshold: 3,
        isFailure: (error) => {
          return error instanceof Error && error.message.includes('critical');
        },
      });

      // 2 non-critical (don't count)
      for (let i = 0; i < 2; i++) {
        try {
          await breaker.execute(async () => {
            throw new Error('minor error');
          });
        } catch {
          // Expected
        }
      }
      expect(breaker.getMetrics().totalFailures).toBe(0);

      // 2 critical (count toward threshold of 3)
      for (let i = 0; i < 2; i++) {
        try {
          await breaker.execute(async () => {
            throw new Error('critical issue');
          });
        } catch {
          // Expected
        }
      }
      expect(breaker.getMetrics().totalFailures).toBe(2);
      expect(breaker.getState()).toBe('CLOSED'); // Not yet at threshold

      // 1 more critical = threshold reached
      try {
        await breaker.execute(async () => {
          throw new Error('critical problem');
        });
      } catch {
        // Expected
      }

      expect(breaker.getState()).toBe('OPEN');
    });
  });

  describe('Metrics', () => {
    test('should track all metrics', async () => {
      const breaker = new CircuitBreaker({ failureThreshold: 5 });

      // 3 successes
      for (let i = 0; i < 3; i++) {
        await breaker.execute(async () => 'success');
      }

      // 2 failures
      for (let i = 0; i < 2; i++) {
        try {
          await breaker.execute(createAlwaysFailingFunction());
        } catch {
          // Expected
        }
      }

      const metrics = breaker.getMetrics();
      expect(metrics.totalRequests).toBe(5);
      expect(metrics.totalSuccesses).toBe(3);
      expect(metrics.totalFailures).toBe(2);
      expect(metrics.lastSuccessTime).not.toBeNull();
      expect(metrics.lastFailureTime).not.toBeNull();
    });
  });

  describe('Manual control', () => {
    test('reset() should close the circuit', async () => {
      const breaker = new CircuitBreaker({ failureThreshold: 1 });

      // Open the circuit
      try {
        await breaker.execute(createAlwaysFailingFunction());
      } catch {
        // Expected
      }

      expect(breaker.getState()).toBe('OPEN');

      breaker.reset();
      expect(breaker.getState()).toBe('CLOSED');
    });

    test('open() should open the circuit', async () => {
      const breaker = new CircuitBreaker();
      expect(breaker.getState()).toBe('CLOSED');

      breaker.open();
      expect(breaker.getState()).toBe('OPEN');
    });
  });
});

// =============================================================================
// withTimeout Tests
// =============================================================================

describe('withTimeout', () => {
  test('should return result if completed within timeout', async () => {
    const fn = createDelayedFunction('success', 50);
    const result = await withTimeout(fn, 1000);
    expect(result).toBe('success');
  });

  test('should throw TimeoutError if timeout exceeded', async () => {
    const fn = createDelayedFunction('success', 200);

    await expect(withTimeout(fn, 50, 'slowOperation')).rejects.toThrow(TimeoutError);
  });

  test('should include operation name in error', async () => {
    const fn = createDelayedFunction('success', 200);

    try {
      await withTimeout(fn, 50, 'myOperation');
    } catch (error) {
      expect(error).toBeInstanceOf(TimeoutError);
      expect((error as TimeoutError).message).toContain('myOperation');
    }
  });

  test('should include timeout duration in error properties', async () => {
    const fn = createDelayedFunction('success', 200);

    try {
      await withTimeout(fn, 50, 'myOperation');
    } catch (error) {
      expect(error).toBeInstanceOf(TimeoutError);
      // timeoutMs is a direct property on TimeoutError
      expect((error as TimeoutError).timeoutMs).toBe(50);
    }
  });

  test('should propagate errors from the function', async () => {
    const fn = async () => {
      await new Promise((resolve) => setTimeout(resolve, 10));
      throw new Error('Function error');
    };

    await expect(withTimeout(fn, 1000)).rejects.toThrow('Function error');
  });

  test('should clear timeout on error', async () => {
    const fn = async () => {
      throw new Error('Immediate error');
    };

    const startTime = Date.now();
    await expect(withTimeout(fn, 5000)).rejects.toThrow('Immediate error');

    // Should not wait for timeout
    expect(Date.now() - startTime).toBeLessThan(500);
  });
});

// =============================================================================
// withResilience Tests (Combined Retry + Circuit Breaker)
// =============================================================================

describe('withResilience', () => {
  test('should combine retry and circuit breaker', async () => {
    const breaker = new CircuitBreaker({
      failureThreshold: 5,
      resetTimeoutMs: 10000,
    });

    // Should retry and eventually succeed
    const fn = createFailingFunction(2, 'success');
    const result = await withResilience(fn, breaker, {
      maxAttempts: 3,
      initialDelayMs: 10,
      jitter: false,
    });

    expect(result).toBe('success');
  });

  test('should fail fast when circuit is open', async () => {
    const breaker = new CircuitBreaker({
      failureThreshold: 1,
      resetTimeoutMs: 10000,
    });

    // Open the circuit
    try {
      await withResilience(createAlwaysFailingFunction(), breaker);
    } catch {
      // Expected
    }

    expect(breaker.getState()).toBe('OPEN');

    // Should fail fast without retrying
    const startTime = Date.now();
    await expect(
      withResilience(async () => 'success', breaker, {
        maxAttempts: 5,
        initialDelayMs: 1000,
      })
    ).rejects.toThrow(ServiceUnavailableError);

    expect(Date.now() - startTime).toBeLessThan(500);
  });

  test('should count each withResilience call as one circuit breaker execution', async () => {
    const breaker = new CircuitBreaker({
      failureThreshold: 3,
      resetTimeoutMs: 10000,
    });

    // Each withResilience call counts as 1 failure for circuit breaker
    // (even if there are multiple retries inside)
    for (let i = 0; i < 3; i++) {
      try {
        await withResilience(createAlwaysFailingFunction(), breaker, {
          maxAttempts: 2,
          initialDelayMs: 10,
          jitter: false,
        });
      } catch {
        // Expected
      }
    }

    // Circuit should now be open after 3 failed calls
    expect(breaker.getState()).toBe('OPEN');
  });
});

// =============================================================================
// Integration Tests - Maximo-like Scenarios
// =============================================================================

describe('Integration: Maximo Integration Scenarios', () => {
  // Fast retry config for tests (avoids long delays)
  const FAST_RETRY_CONFIG: Partial<RetryConfig> = {
    maxAttempts: 5,
    initialDelayMs: 10,
    maxDelayMs: 100,
    backoffMultiplier: 2,
    jitter: false,
    isRetryable: EXTERNAL_SERVICE_RETRY_CONFIG.isRetryable,
  };

  test('should handle intermittent Maximo failures', async () => {
    const breaker = new CircuitBreaker({
      failureThreshold: 5,
      successThreshold: 2,
      resetTimeoutMs: 100,
    });

    let attempts = 0;
    const maximoLikeFn = async () => {
      attempts++;
      // Fails 2 times, then succeeds
      if (attempts <= 2) {
        throw new ExternalServiceError('Maximo connection reset');
      }
      return { workOrderId: 'WO-123' };
    };

    const result = await withResilience(maximoLikeFn, breaker, FAST_RETRY_CONFIG);

    expect(result).toEqual({ workOrderId: 'WO-123' });
    expect(breaker.getState()).toBe('CLOSED');
  });

  test('should open circuit after sustained Maximo outage', async () => {
    const breaker = new CircuitBreaker({
      failureThreshold: 5,
      resetTimeoutMs: 1000,
    });

    // Simulate sustained outage - need 5 failed calls to open circuit
    const maximoLikeFn = createAlwaysFailingFunction(
      new ExternalServiceError('Maximo service unavailable')
    );

    // Multiple request batches (5 calls to reach threshold)
    for (let batch = 0; batch < 5; batch++) {
      try {
        await withResilience(maximoLikeFn, breaker, {
          maxAttempts: 2,
          initialDelayMs: 10,
          jitter: false,
        });
      } catch {
        // Expected
      }
    }

    // Circuit should be open after accumulated failures
    expect(breaker.getState()).toBe('OPEN');

    // New requests should fail fast
    await expect(withResilience(async () => 'success', breaker)).rejects.toThrow(
      ServiceUnavailableError
    );
  });

  test('should recover from Maximo outage gracefully', async () => {
    const stateChanges: CircuitState[] = [];
    const breaker = new CircuitBreaker({
      failureThreshold: 2,
      successThreshold: 2,
      resetTimeoutMs: 50,
      onStateChange: (_from, to) => {
        stateChanges.push(to);
      },
    });

    // Open circuit with failures
    for (let i = 0; i < 2; i++) {
      try {
        await breaker.execute(createAlwaysFailingFunction(new ExternalServiceError('Outage')));
      } catch {
        // Expected
      }
    }

    expect(breaker.getState()).toBe('OPEN');

    // Wait for recovery window
    await new Promise((resolve) => setTimeout(resolve, 100));

    // Service has recovered
    const result = await breaker.execute(async () => 'recovered');
    expect(result).toBe('recovered');

    // One more success to close circuit
    await breaker.execute(async () => 'recovered');

    expect(breaker.getState()).toBe('CLOSED');
    expect(stateChanges).toContain('OPEN');
    expect(stateChanges).toContain('HALF_OPEN');
    expect(stateChanges).toContain('CLOSED');
  });
});

