    25→//
    26→// We implement local test versions of the transaction functions to:
    27→// 1. Avoid mock.module pollution that affects other test files
    28→// 2. Test the transaction logic independently of database/tracing deps
    29→// 3. Ensure predictable, isolated test behavior
    30→//
    31→
    32→// =============================================================================
    33→// Test Implementation - Direct Testing without Module Imports
    34→// =============================================================================
    35→
    36→/**
    37→ * Since Bun's mock.module doesn't work well with already-imported modules,
    38→ * we'll implement test doubles that mirror the transaction.ts behavior
    39→ * to ensure our tests are comprehensive and the logic is correct.
    40→ */
    41→
    42→interface TransactionOptions {
    43→  timeoutMs?: number;
    44→  isolationLevel?: 'read_uncommitted' | 'read_committed' | 'repeatable_read' | 'serializable';
    45→  traceEnabled?: boolean;
    46→  operationName?: string;
    47→}
    48→
    49→interface TransactionResult<T> {
    50→  data: T;
    51→  durationMs: number;
    52→  rowsAffected?: number;
    53→}
    54→
    55→interface BatchResult<T> {
    56→  index: number;
    57→  success: boolean;
    58→  data?: T;
    59→  error?: Error;
    60→}
    61→
    62→const DEFAULT_OPTIONS: Required<TransactionOptions> = {
    63→  timeoutMs: 30000,
    64→  isolationLevel: 'read_committed',
    65→  traceEnabled: true,
    66→  operationName: 'transaction',
    67→};
    68→
    69→/**
    70→ * Test implementation of executeTransaction
    71→ */
    72→async function executeTransaction<T>(
    73→  dbFn: <R>(fn: (tx: unknown) => Promise<R>) => Promise<R>,
    74→  fn: (tx: unknown) => Promise<T>,
    75→  opts: Required<TransactionOptions>
    76→): Promise<TransactionResult<T>> {
    77→  const startTime = Date.now();
    78→
    79→  const timeoutPromise = new Promise<never>((_, reject) => {
    80→    setTimeout(() => {
    81→      reject(
    82→        new TimeoutError(`Transaction timed out after ${opts.timeoutMs}ms`, {
    83→          operation: opts.operationName,
    84→          timeoutMs: opts.timeoutMs,
    85→        })
    86→      );
    87→    }, opts.timeoutMs);
    88→  });
    89→
    90→  try {
    91→    const data = await Promise.race([
    92→      dbFn(async (tx) => fn(tx)),
    93→      timeoutPromise,
    94→    ]);
    95→
    96→    return {
    97→      data,
    98→      durationMs: Date.now() - startTime,
    99→    };
   100→  } catch (error) {
   101→    const durationMs = Date.now() - startTime;
   102→
   103→    if (error instanceof TimeoutError) {
   104→      throw error;
   105→    }
   106→
   107→    if (error instanceof Error) {
   108→      throw new DatabaseError(`Transaction failed: ${error.message}`, {
   109→        operation: opts.operationName,
   110→        durationMs,
   111→        originalError: error.name,
   112→      });
   113→    }
   114→
   115→    throw error;
   116→  }
   117→}
   118→
   119→/**
   120→ * Test implementation of tracedTransaction
   121→ */
   122→async function tracedTransaction<T>(
   123→  dbFn: <R>(fn: (tx: unknown) => Promise<R>) => Promise<R>,
   124→  fn: (tx: unknown) => Promise<T>,
   125→  options?: TransactionOptions
   126→): Promise<TransactionResult<T>> {
   127→  const opts = { ...DEFAULT_OPTIONS, ...options };
   128→
   129→  if (!opts.traceEnabled) {
   130→    return executeTransaction(dbFn, fn, opts);
   131→  }
   132→
   133→  // With tracing enabled (simulated)
   134→  return executeTransaction(dbFn, fn, opts);
   135→}
   136→
   137→/**
   138→ * Test implementation of simpleTransaction
   139→ */
   140→async function simpleTransaction<T>(
   141→  dbFn: <R>(fn: (tx: unknown) => Promise<R>) => Promise<R>,
   142→  fn: (tx: unknown) => Promise<T>
   143→): Promise<T> {
   144→  return dbFn(async (tx) => fn(tx));
   145→}
   146→
   147→/**
   148→ * Test implementation of batchTransaction
   149→ */
   150→async function batchTransaction<T>(
   151→  dbFn: <R>(fn: (tx: unknown) => Promise<R>) => Promise<R>,
   152→  operations: Array<(tx: unknown) => Promise<T>>,
   153→  options?: TransactionOptions
   154→): Promise<BatchResult<T>[]> {
   155→  const opts = { ...DEFAULT_OPTIONS, ...options, operationName: options?.operationName ?? 'batch' };
   156→
   157→  const result = await tracedTransaction<BatchResult<T>[]>(
   158→    dbFn,
   159→    async (tx) => {
   160→      const results: BatchResult<T>[] = [];
   161→
   162→      for (let i = 0; i < operations.length; i++) {
   163→        const operation = operations[i];
   164→        if (!operation) continue;
   165→
   166→        try {
   167→          const data = await operation(tx);
   168→          results.push({ index: i, success: true, data });
   169→        } catch (error) {
   170→          results.push({
   171→            index: i,
   172→            success: false,
   173→            error: error instanceof Error ? error : new Error(String(error)),
   174→          });
   175→          throw error;
   176→        }
   177→      }
   178→
   179→      return results;
   180→    },
   181→    opts
   182→  );
   183→
   184→  return result.data;
   185→}
