describe('Integration: Transaction Workflows', () => {
  test('should handle typical PM scheduling transaction', async () => {
    const mockDbFn = async <T>(fn: (tx: unknown) => Promise<T>) => fn({
      insert: () => ({ values: () => Promise.resolve({ rowCount: 1 }) }),
      update: () => ({ set: () => ({ where: () => Promise.resolve({ rowCount: 1 }) }) }),
    });

    const result = await tracedTransaction(
      mockDbFn,
      async (tx) => {
        // Simulate PM scheduling operations
        const txTyped = tx as {
          insert: () => { values: () => Promise<{ rowCount: number }> };
          update: () => { set: () => { where: () => Promise<{ rowCount: number }> } };
        };

        await txTyped.insert().values();
        await txTyped.update().set().where();

        return { scheduleId: 'PM-001', trainId: 'T001', status: 'SCHEDULED' };
      },
      { operationName: 'schedulePM' }
    );

    expect(result.data).toEqual({
      scheduleId: 'PM-001',
      trainId: 'T001',
      status: 'SCHEDULED',
    });
  });

  test('should handle typical batch mileage update', async () => {
    const mockDbFn = async <T>(fn: (tx: unknown) => Promise<T>) => fn({});

    const trainMileages = [
      { trainId: 'T001', mileage: 150000 },
      { trainId: 'T002', mileage: 145000 },
      { trainId: 'T003', mileage: 160000 },
    ];

    const results = await batchTransaction(
      mockDbFn,
      trainMileages.map((tm) => async () => ({
        trainId: tm.trainId,
        previousMileage: tm.mileage - 300,
        newMileage: tm.mileage,
        updated: true,
      })),
      { operationName: 'batchMileageUpdate' }
    );

    expect(results).toHaveLength(3);
    expect(results.every((r) => r.success)).toBe(true);
    expect(results[0].data).toEqual({
      trainId: 'T001',
      previousMileage: 149700,
      newMileage: 150000,
      updated: true,
    });
  });

  test('should maintain data integrity on partial failure', async () => {
    let insertedRecords = 0;
    const mockDbFn = async <T>(fn: (tx: unknown) => Promise<T>) => {
      const preInsertCount = insertedRecords;
      try {
        return await fn({});
      } catch (error) {
        // Rollback: reset to pre-transaction state
        insertedRecords = preInsertCount;
        throw error;
      }
    };

    try {
      await batchTransaction(
        mockDbFn,
        [
          async () => { insertedRecords++; return 'record1'; },
          async () => { insertedRecords++; return 'record2'; },
          async () => { throw new Error('Constraint violation'); },
          async () => { insertedRecords++; return 'record4'; },
        ]
      );
    } catch {
      // Expected
    }

    // Due to rollback, no records should be inserted
    expect(insertedRecords).toBe(0);
  });

  test('should handle nested async operations within transaction', async () => {
    const mockDbFn = async <T>(fn: (tx: unknown) => Promise<T>) => fn({});

    const result = await tracedTransaction(
      mockDbFn,
      async () => {
        // Simulate multiple async database operations
        const trainResult = await Promise.resolve({ id: 'T001', name: 'Train Alpha' });
        const pmResult = await Promise.resolve({ id: 'PM001', trainId: 'T001' });
        const auditResult = await Promise.resolve({ logged: true, timestamp: new Date() });

        return {
          train: trainResult,
          pm: pmResult,
          audit: auditResult,
        };
      }
    );

    expect(result.data.train).toEqual({ id: 'T001', name: 'Train Alpha' });
    expect(result.data.pm).toEqual({ id: 'PM001', trainId: 'T001' });
    expect(result.data.audit.logged).toBe(true);
  });
});

