describe('Edge Cases', () => {
  test('should handle null return value from transaction', async () => {
    const mockDbFn = async <T>(fn: (tx: unknown) => Promise<T>) => fn({});

    const result = await tracedTransaction(mockDbFn, async () => null);

    expect(result.data).toBeNull();
  });

  test('should handle undefined return value from transaction', async () => {
    const mockDbFn = async <T>(fn: (tx: unknown) => Promise<T>) => fn({});

    const result = await tracedTransaction(mockDbFn, async () => undefined);

    expect(result.data).toBeUndefined();
  });

  test('should handle very fast transactions', async () => {
    const mockDbFn = async <T>(fn: (tx: unknown) => Promise<T>) => fn({});

    const result = await tracedTransaction(mockDbFn, async () => 'instant');

    expect(result.data).toBe('instant');
    expect(result.durationMs).toBeGreaterThanOrEqual(0);
  });

  test('should handle large data payloads', async () => {
    const mockDbFn = async <T>(fn: (tx: unknown) => Promise<T>) => fn({});

    const largeArray = Array.from({ length: 10000 }, (_, i) => ({
      id: `item-${i}`,
      data: `data-${i}`.repeat(10),
    }));

    const result = await tracedTransaction(mockDbFn, async () => largeArray);

    expect(result.data).toHaveLength(10000);
    expect(result.data[0]).toEqual({ id: 'item-0', data: 'data-0'.repeat(10) });
  });

  test('should re-throw non-Error exceptions', async () => {
    const mockDbFn = async <T>(fn: (tx: unknown) => Promise<T>) => fn({});
    const stringError = 'string error';

    await expect(
      tracedTransaction(mockDbFn, async () => {
        throw stringError;
      })
    ).rejects.toBe('string error');
  });

  test('should handle concurrent transactions', async () => {
    const mockDbFn = async <T>(fn: (tx: unknown) => Promise<T>) => fn({});

    const results = await Promise.all([
      tracedTransaction(mockDbFn, async () => 'tx1'),
      tracedTransaction(mockDbFn, async () => 'tx2'),
      tracedTransaction(mockDbFn, async () => 'tx3'),
    ]);

    expect(results).toHaveLength(3);
    expect(results[0].data).toBe('tx1');
    expect(results[1].data).toBe('tx2');
    expect(results[2].data).toBe('tx3');
  });
});

