/**
 * MMS Error Classes Unit Tests
 *
 * Tests for error handling infrastructure covering:
 * - Error code assignments (correct codes per category)
 * - HTTP status code mappings
 * - toJSON() serialization for API responses
 * - isMmsError() type guard
 * - toMmsError() conversion from unknown errors
 * - Error-specific properties and options
 *
 * These tests are CRITICAL as error classes provide consistent error handling
 * across the 12-year government contract, enabling proper API responses,
 * logging, and client-side error handling.
 *
 * @see src/lib/errors/index.ts
 * @see specs/004-domain-services.md - Error handling patterns
 */

import { describe, test, expect } from 'bun:test';
import {
  // Base class
  MmsError,
  // Validation Errors (400)
  ValidationError,
  CsvValidationError,
  RowValidationError,
  FileError,
  // Authentication Errors (401)
  AuthenticationError,
  TokenExpiredError,
  InvalidTokenError,
  // Authorization Errors (403)
  AuthorizationError,
  DepotAccessError,
  // Not Found Errors (404)
  NotFoundError,
  TrainNotFoundError,
  PmScheduleNotFoundError,
  // Conflict Errors (409)
  ConflictError,
  DuplicateError,
  MaximoLockError,
  TrackConflictError,
  // Business Logic Errors (422)
  BusinessRuleError,
  ComplianceWindowError,
  MaterialConstraintError,
  ServiceDemandViolationError,
  // System Errors (500)
  SystemError,
  DatabaseError,
  RedisError,
  QueueError,
  // External System Errors (502, 503, 504)
  ExternalServiceError,
  MaximoConnectionError,
  ServiceUnavailableError,
  TimeoutError,
  // Utilities
  isMmsError,
  toMmsError,
  ERROR_CODES,
} from './index';

// =============================================================================
// Base MmsError Tests
// =============================================================================

describe('MmsError Base Class', () => {
  test('should set name to constructor name', () => {
    const error = new ValidationError('Test error');
    expect(error.name).toBe('ValidationError');
  });

  test('should set message correctly', () => {
    const error = new ValidationError('Custom message');
    expect(error.message).toBe('Custom message');
  });

  test('should be an instance of Error', () => {
    const error = new ValidationError('Test');
    expect(error).toBeInstanceOf(Error);
    expect(error).toBeInstanceOf(MmsError);
  });

  test('should capture stack trace', () => {
    const error = new ValidationError('Test');
    expect(error.stack).toBeDefined();
    expect(error.stack).toContain('ValidationError');
  });

  test('should include timestamp', () => {
    const before = new Date();
    const error = new ValidationError('Test');
    const after = new Date();
    expect(error.timestamp).toBeInstanceOf(Date);
    expect(error.timestamp.getTime()).toBeGreaterThanOrEqual(before.getTime());
    expect(error.timestamp.getTime()).toBeLessThanOrEqual(after.getTime());
  });

  test('should accept optional context', () => {
    const context = { userId: 'user-123', action: 'validate' };
    const error = new ValidationError('Test', { context });
    expect(error.context).toEqual(context);
  });

  test('should default isOperational to true', () => {
    const error = new ValidationError('Test');
    expect(error.isOperational).toBe(true);
  });

  describe('toJSON()', () => {
    test('should serialize to JSON with all required fields', () => {
      const error = new ValidationError('Invalid input');
      const json = error.toJSON();

      expect(json.name).toBe('ValidationError');
      expect(json.code).toBe('BUS_001');
      expect(json.message).toBe('Invalid input');
      expect(json.statusCode).toBe(400);
      expect(json.timestamp).toBeDefined();
      expect(typeof json.timestamp).toBe('string');
    });

    test('should include context when present', () => {
      const context = { field: 'email', userId: 'user-456' };
      const error = new ValidationError('Invalid email', { context });
      const json = error.toJSON();

      expect(json.context).toEqual(context);
    });

    test('should omit context when not present', () => {
      const error = new ValidationError('Test');
      const json = error.toJSON();

      expect(json.context).toBeUndefined();
    });

    test('should produce valid ISO 8601 timestamp', () => {
      const error = new ValidationError('Test');
      const json = error.toJSON();

      const parsed = new Date(json.timestamp);
      expect(parsed.toISOString()).toBe(json.timestamp);
    });
  });
});

// =============================================================================
// Validation Errors (400) Tests
// =============================================================================

describe('Validation Errors (400)', () => {
  describe('ValidationError', () => {
    test('should have correct code and statusCode', () => {
      const error = new ValidationError('Invalid input');
      expect(error.code).toBe('BUS_001');
      expect(error.statusCode).toBe(400);
    });

    test('should accept field option', () => {
      const error = new ValidationError('Invalid email', { field: 'email' });
      expect(error.field).toBe('email');
    });

    test('should accept errors array', () => {
      const errors = [
        { field: 'name', message: 'Required' },
        { field: 'email', message: 'Invalid format' },
      ];
      const error = new ValidationError('Multiple errors', { errors });
      expect(error.errors).toEqual(errors);
      expect(error.errors).toHaveLength(2);
    });
  });

  describe('CsvValidationError', () => {
    test('should have correct code and statusCode', () => {
      const error = new CsvValidationError('Invalid CSV format');
      expect(error.code).toBe('FILE_001');
      expect(error.statusCode).toBe(400);
    });

    test('should accept row and column options', () => {
      const error = new CsvValidationError('Invalid value', {
        row: 42,
        column: 'mileage',
      });
      expect(error.row).toBe(42);
      expect(error.column).toBe('mileage');
    });
  });

  describe('RowValidationError', () => {
    test('should have correct code and statusCode', () => {
      const error = new RowValidationError('Invalid row', 10);
      expect(error.code).toBe('ROW_001');
      expect(error.statusCode).toBe(400);
    });

    test('should require row number', () => {
      const error = new RowValidationError('Test', 25);
      expect(error.row).toBe(25);
    });

    test('should accept column and value options', () => {
      const error = new RowValidationError('Invalid value', 5, {
        column: 'odometer',
        value: -100,
      });
      expect(error.column).toBe('odometer');
      expect(error.value).toBe(-100);
    });
  });

  describe('FileError', () => {
    test('should have correct code and statusCode', () => {
      const error = new FileError('File not found');
      expect(error.code).toBe('FILE_002');
      expect(error.statusCode).toBe(400);
    });

    test('should accept filePath and operation options', () => {
      const error = new FileError('Cannot read file', {
        filePath: '/data/mileage.csv',
        operation: 'read',
      });
      expect(error.filePath).toBe('/data/mileage.csv');
      expect(error.operation).toBe('read');
    });
  });
});

// =============================================================================
// Authentication Errors (401) Tests
// =============================================================================

describe('Authentication Errors (401)', () => {
  describe('AuthenticationError', () => {
    test('should have correct code and statusCode', () => {
      const error = new AuthenticationError('Not authenticated');
      expect(error.code).toBe('AUTH_001');
      expect(error.statusCode).toBe(401);
    });
  });

  describe('TokenExpiredError', () => {
    test('should have correct code and statusCode', () => {
      const error = new TokenExpiredError('Token has expired');
      expect(error.code).toBe('AUTH_002');
      expect(error.statusCode).toBe(401);
    });
  });

  describe('InvalidTokenError', () => {
    test('should have correct code and statusCode', () => {
      const error = new InvalidTokenError('Token is malformed');
      expect(error.code).toBe('AUTH_003');
      expect(error.statusCode).toBe(401);
    });
  });
});

// =============================================================================
// Authorization Errors (403) Tests
// =============================================================================

describe('Authorization Errors (403)', () => {
  describe('AuthorizationError', () => {
    test('should have correct code and statusCode', () => {
      const error = new AuthorizationError('Access denied');
      expect(error.code).toBe('AUTH_010');
      expect(error.statusCode).toBe(403);
    });

    test('should accept requiredPermission option', () => {
      const error = new AuthorizationError('Permission denied', {
        requiredPermission: 'pm:schedule:write',
      });
      expect(error.requiredPermission).toBe('pm:schedule:write');
    });
  });

  describe('DepotAccessError', () => {
    test('should have correct code and statusCode', () => {
      const error = new DepotAccessError('Cannot access depot', 'depot-001');
      expect(error.code).toBe('AUTH_011');
      expect(error.statusCode).toBe(403);
    });

    test('should include depot ID', () => {
      const error = new DepotAccessError('Access denied', 'depot-xyz');
      expect(error.depotId).toBe('depot-xyz');
    });
  });
});

// =============================================================================
// Not Found Errors (404) Tests
// =============================================================================

describe('Not Found Errors (404)', () => {
  describe('NotFoundError', () => {
    test('should have correct code and statusCode', () => {
      const error = new NotFoundError('Resource not found');
      expect(error.code).toBe('BUS_010');
      expect(error.statusCode).toBe(404);
    });

    test('should accept entityType and entityId options', () => {
      const error = new NotFoundError('Route not found', {
        entityType: 'route',
        entityId: 'route-001',
      });
      expect(error.entityType).toBe('route');
      expect(error.entityId).toBe('route-001');
    });
  });

  describe('TrainNotFoundError', () => {
    test('should have correct code and statusCode', () => {
      const error = new TrainNotFoundError('T001');
      expect(error.code).toBe('BUS_011');
      expect(error.statusCode).toBe(404);
    });

    test('should auto-generate message with train ID', () => {
      const error = new TrainNotFoundError('T123');
      expect(error.message).toBe('Train not found: T123');
    });

    test('should set entity type and ID', () => {
      const error = new TrainNotFoundError('T456');
      expect(error.entityType).toBe('train');
      expect(error.entityId).toBe('T456');
    });
  });

  describe('PmScheduleNotFoundError', () => {
    test('should have correct code and statusCode', () => {
      const error = new PmScheduleNotFoundError('sched-001');
      expect(error.code).toBe('BUS_012');
      expect(error.statusCode).toBe(404);
    });

    test('should auto-generate message with schedule ID', () => {
      const error = new PmScheduleNotFoundError('pm-456');
      expect(error.message).toBe('PM schedule not found: pm-456');
    });

    test('should set entity type and ID', () => {
      const error = new PmScheduleNotFoundError('pm-789');
      expect(error.entityType).toBe('pm_schedule');
      expect(error.entityId).toBe('pm-789');
    });
  });
});

// =============================================================================
// Conflict Errors (409) Tests
// =============================================================================

describe('Conflict Errors (409)', () => {
  describe('ConflictError', () => {
    test('should have correct code and statusCode', () => {
      const error = new ConflictError('Resource conflict');
      expect(error.code).toBe('BUS_020');
      expect(error.statusCode).toBe(409);
    });
  });

  describe('DuplicateError', () => {
    test('should have correct code and statusCode', () => {
      const error = new DuplicateError('Duplicate entry');
      expect(error.code).toBe('BUS_021');
      expect(error.statusCode).toBe(409);
    });

    test('should accept field and value options', () => {
      const error = new DuplicateError('Duplicate train number', {
        field: 'train_number',
        value: 'T001',
      });
      expect(error.field).toBe('train_number');
      expect(error.value).toBe('T001');
    });
  });

  describe('MaximoLockError', () => {
    test('should have correct code and statusCode', () => {
      const error = new MaximoLockError('Work order locked');
      expect(error.code).toBe('EXT_001');
      expect(error.statusCode).toBe(409);
    });

    test('should accept workOrderId and maximoStatus options', () => {
      const error = new MaximoLockError('Cannot modify locked WO', {
        workOrderId: 'WO-12345',
        maximoStatus: 'INPRG',
      });
      expect(error.workOrderId).toBe('WO-12345');
      expect(error.maximoStatus).toBe('INPRG');
    });
  });

  describe('TrackConflictError', () => {
    test('should have correct code and statusCode', () => {
      const error = new TrackConflictError('Track already occupied');
      expect(error.code).toBe('BUS_022');
      expect(error.statusCode).toBe(409);
    });

    test('should accept trackId and conflictingScheduleId options', () => {
      const error = new TrackConflictError('Track in use', {
        trackId: 'track-A1',
        conflictingScheduleId: 'pm-999',
      });
      expect(error.trackId).toBe('track-A1');
      expect(error.conflictingScheduleId).toBe('pm-999');
    });
  });
});

// =============================================================================
// Business Logic Errors (422) Tests
// =============================================================================

describe('Business Logic Errors (422)', () => {
  describe('BusinessRuleError', () => {
    test('should have correct code and statusCode', () => {
      const error = new BusinessRuleError('Business rule violated');
      expect(error.code).toBe('BUS_030');
      expect(error.statusCode).toBe(422);
    });

    test('should accept rule option', () => {
      const error = new BusinessRuleError('Cannot schedule PM', {
        rule: 'MIN_INTERVAL_DAYS',
      });
      expect(error.rule).toBe('MIN_INTERVAL_DAYS');
    });
  });

  describe('ComplianceWindowError', () => {
    test('should have correct code and statusCode', () => {
      const error = new ComplianceWindowError('Outside compliance window');
      expect(error.code).toBe('BUS_031');
      expect(error.statusCode).toBe(422);
    });

    test('should accept window dates and target date', () => {
      const windowStart = new Date('2026-01-01');
      const windowEnd = new Date('2026-03-01');
      const targetDate = new Date('2026-04-15');

      const error = new ComplianceWindowError('Target outside window', {
        windowStart,
        windowEnd,
        targetDate,
      });

      expect(error.windowStart).toEqual(windowStart);
      expect(error.windowEnd).toEqual(windowEnd);
      expect(error.targetDate).toEqual(targetDate);
    });
  });

  describe('MaterialConstraintError', () => {
    test('should have correct code and statusCode', () => {
      const error = new MaterialConstraintError('Insufficient materials');
      expect(error.code).toBe('BUS_032');
      expect(error.statusCode).toBe(422);
    });

    test('should accept material constraint details', () => {
      const error = new MaterialConstraintError('Not enough brake pads', {
        partNumber: 'BP-001',
        requiredQuantity: 10,
        availableQuantity: 3,
      });

      expect(error.partNumber).toBe('BP-001');
      expect(error.requiredQuantity).toBe(10);
      expect(error.availableQuantity).toBe(3);
    });
  });

  describe('ServiceDemandViolationError', () => {
    test('should have correct code and statusCode', () => {
      const error = new ServiceDemandViolationError('Insufficient availability');
      expect(error.code).toBe('BUS_033');
      expect(error.statusCode).toBe(422);
    });

    test('should accept service demand details', () => {
      const error = new ServiceDemandViolationError('Fleet below minimum', {
        fleetId: 'fleet-KS',
        requiredTrains: 20,
        availableTrains: 15,
      });

      expect(error.fleetId).toBe('fleet-KS');
      expect(error.requiredTrains).toBe(20);
      expect(error.availableTrains).toBe(15);
    });
  });
});

// =============================================================================
// System Errors (500) Tests
// =============================================================================

describe('System Errors (500)', () => {
  describe('SystemError', () => {
    test('should have correct code and statusCode', () => {
      const error = new SystemError('Internal error');
      expect(error.code).toBe('SYS_001');
      expect(error.statusCode).toBe(500);
    });

    test('should be non-operational', () => {
      const error = new SystemError('System failure');
      expect(error.isOperational).toBe(false);
    });
  });

  describe('DatabaseError', () => {
    test('should have correct code and statusCode', () => {
      const error = new DatabaseError('Database connection failed');
      expect(error.code).toBe('SYS_002');
      expect(error.statusCode).toBe(500);
    });

    test('should be non-operational', () => {
      const error = new DatabaseError('DB error');
      expect(error.isOperational).toBe(false);
    });
  });

  describe('RedisError', () => {
    test('should have correct code and statusCode', () => {
      const error = new RedisError('Redis connection lost');
      expect(error.code).toBe('SYS_003');
      expect(error.statusCode).toBe(500);
    });

    test('should be non-operational', () => {
      const error = new RedisError('Cache failure');
      expect(error.isOperational).toBe(false);
    });
  });

  describe('QueueError', () => {
    test('should have correct code and statusCode', () => {
      const error = new QueueError('Queue processing failed');
      expect(error.code).toBe('SYS_004');
      expect(error.statusCode).toBe(500);
    });

    test('should accept queueName and jobId options', () => {
      const error = new QueueError('Job failed', {
        queueName: 'ingestion',
        jobId: 'job-12345',
      });
      expect(error.queueName).toBe('ingestion');
      expect(error.jobId).toBe('job-12345');
    });
  });
});

// =============================================================================
// External System Errors (502, 503, 504) Tests
// =============================================================================

describe('External System Errors (502, 503, 504)', () => {
  describe('ExternalServiceError', () => {
    test('should have correct code and statusCode', () => {
      const error = new ExternalServiceError('External service failed');
      expect(error.code).toBe('EXT_010');
      expect(error.statusCode).toBe(502);
    });

    test('should accept service name', () => {
      const error = new ExternalServiceError('Service unavailable', {
        service: 'InventoryAPI',
      });
      expect(error.service).toBe('InventoryAPI');
    });
  });

  describe('MaximoConnectionError', () => {
    test('should have correct code and statusCode', () => {
      const error = new MaximoConnectionError('Connection failed');
      expect(error.code).toBe('EXT_011');
      expect(error.statusCode).toBe(502);
    });

    test('should auto-set service to Maximo', () => {
      const error = new MaximoConnectionError('Timeout');
      expect(error.service).toBe('Maximo');
    });
  });

  describe('ServiceUnavailableError', () => {
    test('should have correct code and statusCode', () => {
      const error = new ServiceUnavailableError('Service temporarily down');
      expect(error.code).toBe('SYS_010');
      expect(error.statusCode).toBe(503);
    });

    test('should accept retryAfter option', () => {
      const error = new ServiceUnavailableError('Rate limited', {
        retryAfter: 60,
      });
      expect(error.retryAfter).toBe(60);
    });
  });

  describe('TimeoutError', () => {
    test('should have correct code and statusCode', () => {
      const error = new TimeoutError('Operation timed out');
      expect(error.code).toBe('SYS_011');
      expect(error.statusCode).toBe(504);
    });

    test('should accept operation and timeoutMs options', () => {
      const error = new TimeoutError('Query timed out', {
        operation: 'strategic-plan',
        timeoutMs: 30000,
      });
      expect(error.operation).toBe('strategic-plan');
      expect(error.timeoutMs).toBe(30000);
    });
  });
});

// =============================================================================
// Error Utilities Tests
// =============================================================================

describe('Error Utilities', () => {
  describe('isMmsError()', () => {
    test('should return true for MmsError instances', () => {
      expect(isMmsError(new ValidationError('test'))).toBe(true);
      expect(isMmsError(new SystemError('test'))).toBe(true);
      expect(isMmsError(new TrainNotFoundError('T001'))).toBe(true);
      expect(isMmsError(new MaximoLockError('test'))).toBe(true);
    });

    test('should return false for regular Error instances', () => {
      expect(isMmsError(new Error('test'))).toBe(false);
      expect(isMmsError(new TypeError('test'))).toBe(false);
      expect(isMmsError(new RangeError('test'))).toBe(false);
    });

    test('should return false for non-error values', () => {
      expect(isMmsError(null)).toBe(false);
      expect(isMmsError(undefined)).toBe(false);
      expect(isMmsError('error string')).toBe(false);
