    expect(new SystemError('')).toBeInstanceOf(MmsError);
    expect(new ExternalServiceError('')).toBeInstanceOf(MmsError);
  });

  test('all errors extend Error', () => {
    expect(new ValidationError('')).toBeInstanceOf(Error);
    expect(new SystemError('')).toBeInstanceOf(Error);
    expect(new TimeoutError('')).toBeInstanceOf(Error);
  });

  test('NotFound subclasses inherit from NotFoundError', () => {
    expect(new TrainNotFoundError('T001')).toBeInstanceOf(NotFoundError);
    expect(new PmScheduleNotFoundError('pm-001')).toBeInstanceOf(NotFoundError);
  });

  test('Maximo errors inherit from appropriate parents', () => {
    expect(new MaximoConnectionError('err')).toBeInstanceOf(ExternalServiceError);
    expect(new MaximoLockError('err')).toBeInstanceOf(MmsError);
  });
});

// =============================================================================
// Context Propagation Tests
// =============================================================================

describe('Context Propagation', () => {
  test('should preserve context through inheritance', () => {
    const context = { requestId: 'req-123', userId: 'user-456' };
    const error = new TrainNotFoundError('T001', context);
    expect(error.context).toEqual(context);
  });

  test('should include context in toJSON()', () => {
    const context = { operation: 'PM_SCHEDULE', trainId: 'T001' };
    const error = new ComplianceWindowError('Outside window', {
      windowStart: new Date('2026-01-01'),
      windowEnd: new Date('2026-03-01'),
      context,
    });

    const json = error.toJSON();
    expect(json.context).toEqual(context);
  });

  test('should handle nested context objects', () => {
    const context = {
      user: { id: 'user-1', role: 'PLANNER' },
      request: { path: '/api/pm', method: 'POST' },
    };
    const error = new AuthorizationError('Forbidden', { context });
    expect(error.context).toEqual(context);
  });
});

// =============================================================================
// Edge Cases and Error Handling Tests
// =============================================================================

describe('Edge Cases', () => {
  test('should handle empty message', () => {
    const error = new ValidationError('');
    expect(error.message).toBe('');
    expect(error.toJSON().message).toBe('');
  });

  test('should handle very long messages', () => {
    const longMessage = 'A'.repeat(10000);
    const error = new ValidationError(longMessage);
    expect(error.message).toBe(longMessage);
    expect(error.toJSON().message).toHaveLength(10000);
  });

  test('should handle special characters in message', () => {
    const specialMessage = 'Error: "Invalid" <train> & route\n\ttab';
    const error = new ValidationError(specialMessage);
    expect(error.message).toBe(specialMessage);
  });

  test('should handle undefined options gracefully', () => {
    const error = new ValidationError('test', undefined);
    expect(error.field).toBeUndefined();
    expect(error.errors).toBeUndefined();
    expect(error.context).toBeUndefined();
  });

  test('should handle null values in context', () => {
    const context = { value: null, nested: { also: null } };
    const error = new ValidationError('test', { context });
    expect(error.context).toEqual(context);
  });

  test('should handle Date objects in context', () => {
    const context = { scheduledAt: new Date('2026-01-15') };
    const error = new ComplianceWindowError('test', { context });
    expect(error.context?.scheduledAt).toBeInstanceOf(Date);
  });
});

