   999→// Integration Tests - Full PM Scheduling Workflow
  1000→// =============================================================================
  1001→
  1002→describe('Integration: PM Scheduling Workflow', () => {
  1003→  test('should correctly calculate next C1 PM window based on mileage', () => {
  1004→    const lastPmDate = new Date('2025-06-01');
  1005→    const lastPmMileage = 50000;
  1006→    const currentMileage = 95000;
  1007→    const c1IntervalKm = 60000;
  1008→    const dailyKmRate = 300;
  1009→
  1010→    // Calculate compliance window
  1011→    const window = calculateComplianceWindow({
  1012→      lastPmDate,
  1013→      intervalKm: c1IntervalKm,
  1014→      currentMileageKm: currentMileage,
  1015→      lastPmMileageKm: lastPmMileage,
  1016→      dailyKmRate,
  1017→    });
  1018→
  1019→    // Target mileage = 50000 + 60000 = 110000
  1020→    // Remaining = 110000 - 95000 = 15000 km
  1021→    // Days to target = 15000 / 300 = 50 days
