    21→    21→import { logger } from '../logging/logger';
    22→    22→
    23→    23→/**
    24→    24→ * Migration lock ID for PostgreSQL advisory lock
    25→    25→ * Using a fixed hash to ensure same lock across processes
    26→    26→ */
    27→    27→const MIGRATION_LOCK_ID = 2147483647; // Max int32 for uniqueness
    28→    28→
    29→    29→/**
    30→    30→ * Migration record stored in the database
    31→    31→ */
    32→    32→export interface MigrationRecord {
    33→    33→  id: number;
    34→    34→  name: string;
    35→    35→  hash: string;
    36→    36→  executedAt: Date;
    37→    37→  executionTimeMs: number;
    38→    38→  rollbackSql?: string;
    39→    39→}
    40→    40→
    41→    41→/**
    42→    42→ * Migration file content
    43→    43→ */
    44→    44→export interface Migration {
    45→    45→  name: string;
    46→    46→  sql: string;
    47→    47→  rollbackSql?: string;
    48→    48→  isManual: boolean;
    49→    49→}
    50→    50→
    51→    51→/**
    52→    52→ * Migration result
    53→    53→ */
    54→    54→export interface MigrationResult {
    55→    55→  name: string;
    56→    56→  status: 'applied' | 'skipped' | 'failed' | 'rolled_back';
    57→    57→  executionTimeMs: number;
    58→    58→  error?: string;
    59→    59→}
    60→    60→
    61→    61→/**
    62→    62→ * Migration options
    63→    63→ */
    64→    64→export interface MigrationOptions {
    65→    65→  /** Run only specific migrations by name */
    66→    66→  filter?: string[];
    67→    67→  /** Dry run - don't actually apply migrations */
    68→    68→  dryRun?: boolean;
    69→    69→  /** Skip manual migrations (extensions, timescaledb, etc.) */
    70→    70→  skipManual?: boolean;
    71→    71→  /** Skip Drizzle-generated migrations */
    72→    72→  skipDrizzle?: boolean;
    73→    73→  /** Include seed data (development only) */
    74→    74→  includeSeed?: boolean;
    75→    75→  /** Progress callback */
    76→    76→  onProgress?: (current: number, total: number, migration: string) => void;
    77→    77→}
    78→    78→
    79→    79→/**
    80→    80→ * Overall migration run result
    81→    81→ */
    82→    82→export interface MigrationRunResult {
    83→    83→  success: boolean;
    84→    84→  migrations: MigrationResult[];
    85→    85→  totalTimeMs: number;
    86→    86→  error?: string;
    87→    87→}
    88→    88→
    89→    89→const log = logger.child({ service: 'migrator' });
    90→    90→
    91→    91→/**
    92→    92→ * Compute a simple hash for migration content
    93→    93→ */
    94→    94→function computeHash(content: string): string {
    95→    95→  let hash = 0;
    96→    96→  for (let i = 0; i < content.length; i++) {
    97→    97→    const char = content.charCodeAt(i);
    98→    98→    hash = ((hash << 5) - hash) + char;
    99→    99→    hash = hash & hash; // Convert to 32-bit integer
   100→   100→  }
   101→   101→  return Math.abs(hash).toString(16).padStart(8, '0');
   102→   102→}
   103→   103→
   104→   104→/**
   105→   105→ * Database Migrator
   106→   106→ *
   107→   107→ * Manages database schema migrations with safety features for production use.
   108→   108→ */
   109→   109→export class Migrator {
   110→   110→  private basePath: string;
   111→   111→
   112→   112→  constructor(basePath?: string) {
   113→   113→    // Default to project root drizzle directory
   114→   114→    this.basePath = basePath ?? join(process.cwd(), 'drizzle');
   115→   115→  }
   116→   116→
   117→   117→  /**
   118→   118→   * Ensure migration history table exists
   119→   119→   */
   120→   120→  async ensureHistoryTable(): Promise<void> {
   121→   121→    await sql`
   122→   122→      CREATE TABLE IF NOT EXISTS __mms_migrations (
   123→   123→        id SERIAL PRIMARY KEY,
   124→   124→        name VARCHAR(255) NOT NULL UNIQUE,
   125→   125→        hash VARCHAR(16) NOT NULL,
   126→   126→        executed_at TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP,
   127→   127→        execution_time_ms INTEGER NOT NULL DEFAULT 0,
   128→   128→        rollback_sql TEXT
   129→   129→      )
   130→   130→    `;
   131→   131→    log.debug('Migration history table ensured');
   132→   132→  }
   133→   133→
   134→   134→  /**
   135→   135→   * Acquire advisory lock for migrations
   136→   136→   *
   137→   137→   * Returns true if lock was acquired, false if another process holds it.
   138→   138→   * Uses pg_try_advisory_lock to avoid blocking.
   139→   139→   */
   140→   140→  async acquireLock(): Promise<boolean> {
   141→   141→    const result = await sql`SELECT pg_try_advisory_lock(${MIGRATION_LOCK_ID}) as acquired`;
   142→   142→    const acquired = result[0]?.acquired === true;
   143→   143→    if (acquired) {
   144→   144→      log.info('Migration lock acquired');
   145→   145→    } else {
   146→   146→      log.warn('Could not acquire migration lock - another process may be running migrations');
   147→   147→    }
   148→   148→    return acquired;
   149→   149→  }
   150→   150→
   151→   151→  /**
   152→   152→   * Release advisory lock
   153→   153→   */
   154→   154→  async releaseLock(): Promise<void> {
   155→   155→    await sql`SELECT pg_advisory_unlock(${MIGRATION_LOCK_ID})`;
   156→   156→    log.info('Migration lock released');
   157→   157→  }
   158→   158→
   159→   159→  /**
   160→   160→   * Get list of applied migrations from history table
   161→   161→   */
   162→   162→  async getAppliedMigrations(): Promise<MigrationRecord[]> {
   163→   163→    await this.ensureHistoryTable();
   164→   164→    const rows = await sql`
   165→   165→      SELECT id, name, hash, executed_at, execution_time_ms, rollback_sql
   166→   166→      FROM __mms_migrations
   167→   167→      ORDER BY id ASC
   168→   168→    `;
   169→   169→    return rows.map(row => ({
   170→   170→      id: row.id as number,
   171→   171→      name: row.name as string,
   172→   172→      hash: row.hash as string,
   173→   173→      executedAt: row.executed_at as Date,
   174→   174→      executionTimeMs: row.execution_time_ms as number,
   175→   175→      rollbackSql: row.rollback_sql as string | undefined,
   176→   176→    }));
   177→   177→  }
   178→   178→
   179→   179→  /**
   180→   180→   * Load manual migrations from drizzle/manual directory
   181→   181→   */
   182→   182→  async loadManualMigrations(): Promise<Migration[]> {
   183→   183→    const manualDir = join(this.basePath, 'manual');
   184→   184→    const migrations: Migration[] = [];
   185→   185→
   186→   186→    try {
   187→   187→      const files = await readdir(manualDir);
   188→   188→      const sqlFiles = files
   189→   189→        .filter(f => f.endsWith('.sql') && !f.startsWith('seed_'))
   190→   190→        .sort();
   191→   191→
   192→   192→      for (const file of sqlFiles) {
   193→   193→        const content = await readFile(join(manualDir, file), 'utf-8');
   194→   194→        migrations.push({
   195→   195→          name: `manual/${file}`,
   196→   196→          sql: content,
   197→   197→          isManual: true,
   198→   198→        });
   199→   199→      }
   200→   200→    } catch {
   201→   201→      // Directory doesn't exist - no manual migrations
   202→   202→      log.debug('No manual migrations directory found');
   203→   203→    }
   204→   204→
   205→   205→    return migrations;
   206→   206→  }
   207→   207→
   208→   208→  /**
   209→   209→   * Load Drizzle-generated migrations from drizzle/migrations directory
   210→   210→   */
   211→   211→  async loadDrizzleMigrations(): Promise<Migration[]> {
   212→   212→    const drizzleDir = join(this.basePath, 'migrations');
   213→   213→    const migrations: Migration[] = [];
   214→   214→
   215→   215→    try {
   216→   216→      const files = await readdir(drizzleDir);
   217→   217→      const sqlFiles = files
   218→   218→        .filter(f => f.endsWith('.sql'))
   219→   219→        .sort();
   220→   220→
   221→   221→      for (const file of sqlFiles) {
   222→   222→        const content = await readFile(join(drizzleDir, file), 'utf-8');
   223→   223→        migrations.push({
   224→   224→          name: `drizzle/${file}`,
   225→   225→          sql: content,
   226→   226→          isManual: false,
   227→   227→        });
   228→   228→      }
   229→   229→    } catch {
   230→   230→      // Directory doesn't exist - need to run drizzle-kit generate
   231→   231→      log.debug('No Drizzle migrations directory found - run "bun run db:generate" first');
   232→   232→    }
   233→   233→
   234→   234→    return migrations;
   235→   235→  }
   236→   236→
   237→   237→  /**
   238→   238→   * Load seed data migration (development only)
   239→   239→   */
   240→   240→  async loadSeedMigration(): Promise<Migration | null> {
   241→   241→    const seedFile = join(this.basePath, 'manual', 'seed_development.sql');
   242→   242→    try {
   243→   243→      const content = await readFile(seedFile, 'utf-8');
   244→   244→      return {
   245→   245→        name: 'seed/seed_development.sql',
   246→   246→        sql: content,
   247→   247→        isManual: true,
   248→   248→      };
   249→   249→    } catch {
   250→   250→      return null;
   251→   251→    }
   252→   252→  }
   253→   253→
   254→   254→  /**
   255→   255→   * Apply a single migration
   256→   256→   */
   257→   257→  async applyMigration(migration: Migration, dryRun: boolean = false): Promise<MigrationResult> {
   258→   258→    const startTime = Date.now();
   259→   259→    const hash = computeHash(migration.sql);
   260→   260→
   261→   261→    if (dryRun) {
   262→   262→      log.info({ migration: migration.name }, 'Would apply migration (dry run)');
   263→   263→      return {
   264→   264→        name: migration.name,
   265→   265→        status: 'skipped',
   266→   266→        executionTimeMs: 0,
   267→   267→      };
   268→   268→    }
   269→   269→
   270→   270→    try {
   271→   271→      // Execute migration SQL
   272→   272→      // For manual migrations with multiple statements, we need unsafe mode
   273→   273→      await sql.unsafe(migration.sql);
   274→   274→
   275→   275→      const executionTimeMs = Date.now() - startTime;
   276→   276→
   277→   277→      // Record in history
   278→   278→      await sql`
   279→   279→        INSERT INTO __mms_migrations (name, hash, execution_time_ms, rollback_sql)
   280→   280→        VALUES (${migration.name}, ${hash}, ${executionTimeMs}, ${migration.rollbackSql ?? null})
   281→   281→        ON CONFLICT (name) DO UPDATE SET
   282→   282→          hash = ${hash},
   283→   283→          executed_at = CURRENT_TIMESTAMP,
   284→   284→          execution_time_ms = ${executionTimeMs}
   285→   285→      `;
   286→   286→
   287→   287→      log.info({ migration: migration.name, executionTimeMs }, 'Migration applied');
   288→   288→
   289→   289→      return {
   290→   290→        name: migration.name,
   291→   291→        status: 'applied',
   292→   292→        executionTimeMs,
   293→   293→      };
   294→   294→    } catch (error) {
   295→   295→      const executionTimeMs = Date.now() - startTime;
   296→   296→      const errorMessage = error instanceof Error ? error.message : String(error);
   297→   297→
   298→   298→      log.error({ migration: migration.name, error: errorMessage }, 'Migration failed');
   299→   299→
   300→   300→      return {
   301→   301→        name: migration.name,
   302→   302→        status: 'failed',
   303→   303→        executionTimeMs,
   304→   304→        error: errorMessage,
   305→   305→      };
   306→   306→    }
   307→   307→  }
   308→   308→
   309→   309→  /**
   310→   310→   * Rollback a migration using its stored rollback SQL
   311→   311→   */
   312→   312→  async rollbackMigration(record: MigrationRecord): Promise<MigrationResult> {
   313→   313→    if (!record.rollbackSql) {
   314→   314→      log.warn({ migration: record.name }, 'No rollback SQL available for migration');
   315→   315→      return {
   316→   316→        name: record.name,
   317→   317→        status: 'skipped',
   318→   318→        executionTimeMs: 0,
   319→   319→        error: 'No rollback SQL available',
   320→   320→      };
   321→   321→    }
   322→   322→
   323→   323→    const startTime = Date.now();
   324→   324→
   325→   325→    try {
   326→   326→      await sql.unsafe(record.rollbackSql);
   327→   327→
   328→   328→      // Remove from history
   329→   329→      await sql`DELETE FROM __mms_migrations WHERE name = ${record.name}`;
   330→   330→
   331→   331→      const executionTimeMs = Date.now() - startTime;
   332→   332→      log.info({ migration: record.name, executionTimeMs }, 'Migration rolled back');
   333→   333→
   334→   334→      return {
   335→   335→        name: record.name,
   336→   336→        status: 'rolled_back',
   337→   337→        executionTimeMs,
   338→   338→      };
   339→   339→    } catch (error) {
   340→   340→      const executionTimeMs = Date.now() - startTime;
   341→   341→      const errorMessage = error instanceof Error ? error.message : String(error);
   342→   342→
   343→   343→      log.error({ migration: record.name, error: errorMessage }, 'Rollback failed');
   344→   344→
   345→   345→      return {
   346→   346→        name: record.name,
   347→   347→        status: 'failed',
   348→   348→        executionTimeMs,
   349→   349→        error: errorMessage,
   350→   350→      };
   351→   351→    }
   352→   352→  }
   353→   353→
   354→   354→  /**
   355→   355→   * Run all pending migrations
   356→   356→   *
   357→   357→   * Executes manual migrations first (extensions, timescaledb, functions),
   358→   358→   * then Drizzle-generated migrations in order.
   359→   359→   */
   360→   360→  async migrate(options: MigrationOptions = {}): Promise<MigrationRunResult> {
   361→   361→    const startTime = Date.now();
   362→   362→    const results: MigrationResult[] = [];
   363→   363→
   364→   364→    log.info({ options }, 'Starting migration run');
   365→   365→
   366→   366→    // Acquire lock
   367→   367→    const lockAcquired = await this.acquireLock();
   368→   368→    if (!lockAcquired) {
   369→   369→      return {
   370→   370→        success: false,
   371→   371→        migrations: [],
   372→   372→        totalTimeMs: Date.now() - startTime,
   373→   373→        error: 'Could not acquire migration lock - another process may be running migrations',
   374→   374→      };
   375→   375→    }
   376→   376→
   377→   377→    try {
   378→   378→      // Get applied migrations
   379→   379→      const applied = await this.getAppliedMigrations();
   380→   380→      const appliedNames = new Set(applied.map(m => m.name));
   381→   381→
   382→   382→      // Load all migrations
   383→   383→      const migrations: Migration[] = [];
   384→   384→
   385→   385→      if (!options.skipManual) {
   386→   386→        const manual = await this.loadManualMigrations();
   387→   387→        migrations.push(...manual);
   388→   388→      }
   389→   389→
   390→   390→      if (!options.skipDrizzle) {
   391→   391→        const drizzle = await this.loadDrizzleMigrations();
   392→   392→        migrations.push(...drizzle);
   393→   393→      }
   394→   394→
   395→   395→      // Filter if specified
   396→   396→      let pending = migrations.filter(m => !appliedNames.has(m.name));
   397→   397→      if (options.filter?.length) {
   398→   398→        pending = pending.filter(m => options.filter!.some(f => m.name.includes(f)));
   399→   399→      }
   400→   400→
   401→   401→      log.info({ total: migrations.length, pending: pending.length }, 'Migrations loaded');
   402→   402→
   403→   403→      // Apply pending migrations
   404→   404→      for (let i = 0; i < pending.length; i++) {
   405→   405→        const migration = pending[i];
   406→   406→        options.onProgress?.(i + 1, pending.length, migration.name);
   407→   407→
   408→   408→        const result = await this.applyMigration(migration, options.dryRun);
   409→   409→        results.push(result);
   410→   410→
   411→   411→        // Stop on failure
   412→   412→        if (result.status === 'failed') {
   413→   413→          log.error({ migration: migration.name }, 'Migration failed - stopping');
   414→   414→          break;
   415→   415→        }
   416→   416→      }
   417→   417→
   418→   418→      // Apply seed data if requested and in development
   419→   419→      if (options.includeSeed && process.env['NODE_ENV'] === 'development') {
   420→   420→        const seed = await this.loadSeedMigration();
   421→   421→        if (seed && !appliedNames.has(seed.name)) {
   422→   422→          options.onProgress?.(pending.length + 1, pending.length + 1, seed.name);
   423→   423→          const result = await this.applyMigration(seed, options.dryRun);
   424→   424→          results.push(result);
   425→   425→        }
   426→   426→      }
   427→   427→
   428→   428→      const success = results.every(r => r.status === 'applied' || r.status === 'skipped');
   429→   429→      const totalTimeMs = Date.now() - startTime;
   430→   430→
   431→   431→      log.info({ success, totalTimeMs, applied: results.filter(r => r.status === 'applied').length }, 'Migration run complete');
   432→   432→
   433→   433→      return {
   434→   434→        success,
   435→   435→        migrations: results,
   436→   436→        totalTimeMs,
   437→   437→      };
   438→   438→    } finally {
   439→   439→      await this.releaseLock();
   440→   440→    }
   441→   441→  }
   442→   442→
   443→   443→  /**
   444→   444→   * Rollback the last N migrations
   445→   445→   */
   446→   446→  async rollback(count: number = 1): Promise<MigrationRunResult> {
   447→   447→    const startTime = Date.now();
   448→   448→    const results: MigrationResult[] = [];
   449→   449→
   450→   450→    log.info({ count }, 'Starting rollback');
   451→   451→
   452→   452→    const lockAcquired = await this.acquireLock();
   453→   453→    if (!lockAcquired) {
   454→   454→      return {
   455→   455→        success: false,
   456→   456→        migrations: [],
   457→   457→        totalTimeMs: Date.now() - startTime,
   458→   458→        error: 'Could not acquire migration lock',
   459→   459→      };
   460→   460→    }
   461→   461→
   462→   462→    try {
   463→   463→      const applied = await this.getAppliedMigrations();
   464→   464→      const toRollback = applied.slice(-count).reverse();
   465→   465→
   466→   466→      for (const record of toRollback) {
   467→   467→        const result = await this.rollbackMigration(record);
   468→   468→        results.push(result);
   469→   469→
   470→   470→        if (result.status === 'failed') {
   471→   471→          break;
   472→   472→        }
   473→   473→      }
   474→   474→
   475→   475→      const success = results.every(r => r.status === 'rolled_back' || r.status === 'skipped');
   476→   476→      const totalTimeMs = Date.now() - startTime;
   477→   477→
   478→   478→      log.info({ success, totalTimeMs, rolledBack: results.filter(r => r.status === 'rolled_back').length }, 'Rollback complete');
   479→   479→
   480→   480→      return {
   481→   481→        success,
   482→   482→        migrations: results,
   483→   483→        totalTimeMs,
   484→   484→      };
   485→   485→    } finally {
   486→   486→      await this.releaseLock();
   487→   487→    }
   488→   488→  }
   489→   489→
   490→   490→  /**
   491→   491→   * Get migration status
   492→   492→   */
   493→   493→  async status(): Promise<{
   494→   494→    applied: MigrationRecord[];
   495→   495→    pending: Migration[];
   496→   496→    hasLock: boolean;
   497→   497→  }> {
   498→   498→    await this.ensureHistoryTable();
   499→   499→
   500→   500→    const applied = await this.getAppliedMigrations();
   501→   501→    const appliedNames = new Set(applied.map(m => m.name));
   502→   502→
   503→   503→    const manual = await this.loadManualMigrations();
   504→   504→    const drizzle = await this.loadDrizzleMigrations();
   505→   505→    const all = [...manual, ...drizzle];
   506→   506→
   507→   507→    const pending = all.filter(m => !appliedNames.has(m.name));
   508→   508→
   509→   509→    // Check if we can acquire the lock
   510→   510→    const hasLock = await this.acquireLock();
   511→   511→    if (hasLock) {
   512→   512→      await this.releaseLock();
   513→   513→    }
   514→   514→
   515→   515→    return { applied, pending, hasLock };
   516→   516→  }
   517→   517→
   518→   518→  /**
   519→   519→   * Verify database connection and prerequisites
   520→   520→   */
   521→   521→  async verify(): Promise<{
   522→   522→    connected: boolean;
   523→   523→    hasTimescaleDb: boolean;
   524→   524→    hasUuidExtension: boolean;
   525→   525→    schemaVersion: string | null;
   526→   526→  }> {
   527→   527→    try {
   528→   528→      // Check connection
   529→   529→      const connectionResult = await sql`SELECT 1 as health`;
   530→   530→      const connected = connectionResult[0]?.health === 1;
   531→   531→
   532→   532→      if (!connected) {
   533→   533→        return {
   534→   534→          connected: false,
   535→   535→          hasTimescaleDb: false,
   536→   536→          hasUuidExtension: false,
   537→   537→          schemaVersion: null,
   538→   538→        };
   539→   539→      }
   540→   540→
   541→   541→      // Check TimescaleDB extension
   542→   542→      const tsResult = await sql`
   543→   543→        SELECT EXISTS(
   544→   544→          SELECT 1 FROM pg_extension WHERE extname = 'timescaledb'
   545→   545→        ) as has_timescaledb
   546→   546→      `;
   547→   547→      const hasTimescaleDb = tsResult[0]?.has_timescaledb === true;
   548→   548→
   549→   549→      // Check UUID extension
   550→   550→      const uuidResult = await sql`
   551→   551→        SELECT EXISTS(
   552→   552→          SELECT 1 FROM pg_extension WHERE extname = 'uuid-ossp'
   553→   553→        ) as has_uuid
   554→   554→      `;
   555→   555→      const hasUuidExtension = uuidResult[0]?.has_uuid === true;
   556→   556→
   557→   557→      // Get latest migration
   558→   558→      let schemaVersion: string | null = null;
   559→   559→      try {
   560→   560→        const versionResult = await sql`
   561→   561→          SELECT name FROM __mms_migrations ORDER BY id DESC LIMIT 1
   562→   562→        `;
   563→   563→        schemaVersion = versionResult[0]?.name as string | null;
   564→   564→      } catch {
   565→   565→        // History table doesn't exist yet
   566→   566→      }
   567→   567→
   568→   568→      return {
   569→   569→        connected,
   570→   570→        hasTimescaleDb,
   571→   571→        hasUuidExtension,
   572→   572→        schemaVersion,
   573→   573→      };
   574→   574→    } catch (error) {
   575→   575→      log.error({ error }, 'Database verification failed');
   576→   576→      return {
   577→   577→        connected: false,
   578→   578→        hasTimescaleDb: false,
   579→   579→        hasUuidExtension: false,
   580→   580→        schemaVersion: null,
   581→   581→      };
   582→   582→    }
   583→   583→  }
   584→   584→}
   585→   585→
   586→   586→/**
   587→   587→ * Singleton migrator instance
   588→   588→ */
   589→   589→let migratorInstance: Migrator | null = null;
   590→   590→
   591→   591→/**
   592→   592→ * Get the migrator instance
   593→   593→ */
   594→   594→export function getMigrator(): Migrator {
   595→   595→  if (!migratorInstance) {
   596→   596→    migratorInstance = new Migrator();
   597→   597→  }
   598→   598→  return migratorInstance;
   599→   599→}
   600→   600→
   601→   601→/**
   602→   602→ * Run migrations (convenience function)
   603→   603→ */
   604→   604→export async function runMigrations(options?: MigrationOptions): Promise<MigrationRunResult> {
   605→   605→  return getMigrator().migrate(options);
   606→   606→}
   607→   607→
   608→   608→/**
   609→   609→ * Rollback migrations (convenience function)
   610→   610→ */
   611→   611→export async function rollbackMigrations(count?: number): Promise<MigrationRunResult> {
   612→   612→  return getMigrator().rollback(count);
   613→   613→}
   614→   614→
   615→   615→/**
   616→   616→ * Get migration status (convenience function)
   617→   617→ */
   618→   618→export async function getMigrationStatus(): Promise<ReturnType<Migrator['status']>> {
   619→   619→  return getMigrator().status();
   620→   620→}
   621→   621→
   622→   622→/**
   623→   623→ * Verify database prerequisites (convenience function)
   624→   624→ */
   625→   625→export async function verifyDatabase(): Promise<ReturnType<Migrator['verify']>> {
   626→   626→  return getMigrator().verify();
