     1→     1→/**
     2→     2→ * MMS Queue Configuration
     3→     3→ *
     4→     4→ * BullMQ queue setup for background job processing.
     5→     5→ * All queue operations go through Redis for distributed processing.
     6→     6→ *
     7→     7→ * Queue types:
     8→     8→ * - ingestion: CSV file processing and mileage data import
     9→     9→ * - tactical_scheduler: PM scheduling within 12-week horizon
    10→    10→ * - strategic_planner: Long-term (10-year) PM planning
    11→    11→ * - optimizer: Run assignment optimization (CP-SAT)
    12→    12→ * - manhour_leveling: Workload balancing across periods
    13→    13→ * - drift_monitor: Baseline comparison and drift detection
    14→    14→ * - notification: Email and alert sending
    15→    15→ * - report: PDF/Excel report generation
    16→    16→ *
    17→    17→ * @see specs/004-backend-specification.md Section 4.8
    18→    18→ */
    19→    19→
    20→    20→import { Queue, Worker, QueueEvents, type JobsOptions, type WorkerOptions } from 'bullmq';
    21→    21→
    22→    22→// =============================================================================
    23→    23→// Queue Names
    24→    24→// =============================================================================
    25→    25→
    26→    26→export const QUEUE_NAMES = {
    27→    27→  INGESTION: 'mms:ingestion',
    28→    28→  TACTICAL_SCHEDULER: 'mms:tactical-scheduler',
    29→    29→  STRATEGIC_PLANNER: 'mms:strategic-planner',
    30→    30→  OPTIMIZER: 'mms:optimizer',
    31→    31→  MANHOUR_LEVELING: 'mms:manhour-leveling',
    32→    32→  DRIFT_MONITOR: 'mms:drift-monitor',
    33→    33→  NOTIFICATION: 'mms:notification',
    34→    34→  REPORT: 'mms:report',
    35→    35→  MAXIMO_SYNC: 'mms:maximo-sync',
    36→    36→} as const;
    37→    37→
    38→    38→export type QueueName = (typeof QUEUE_NAMES)[keyof typeof QUEUE_NAMES];
    39→    39→
    40→    40→// =============================================================================
    41→    41→// Redis Configuration
    42→    42→// =============================================================================
    43→    43→
    44→    44→function getRedisConfig() {
    45→    45→  return {
    46→    46→    host: process.env['REDIS_HOST'] ?? 'localhost',
    47→    47→    port: parseInt(process.env['REDIS_PORT'] ?? '6379', 10),
    48→    48→    password: process.env['REDIS_PASSWORD'],
    49→    49→    maxRetriesPerRequest: null as null, // Required for BullMQ
    50→    50→  };
    51→    51→}
    52→    52→
    53→    53→// =============================================================================
    54→    54→// Job Types
    55→    55→// =============================================================================
    56→    56→
    57→    57→export interface IngestionJobData {
    58→    58→  filePath: string;
    59→    59→  fileName: string;
    60→    60→  fileSize: number;
    61→    61→  uploadedBy?: string;
    62→    62→}
    63→    63→
    64→    64→export interface TacticalSchedulerJobData {
    65→    65→  fleetId?: string;
    66→    66→  trainIds?: string[];
    67→    67→  horizonWeeks?: number;
    68→    68→  dryRun?: boolean;
    69→    69→}
    70→    70→
    71→    71→export interface StrategicPlannerJobData {
    72→    72→  fleetId?: string;
    73→    73→  horizonYears?: number;
    74→    74→  populationSize?: number;
    75→    75→  generations?: number;
    76→    76→}
    77→    77→
    78→    78→export interface OptimizerJobData {
    79→    79→  date: string;
    80→    80→  fleetId: string;
    81→    81→  constraints?: {
    82→    82→    serviceRequirements?: Record<string, number>;
    83→    83→    unavailableTrains?: string[];
    84→    84→    preferredAssignments?: Record<string, string>;
    85→    85→  };
    86→    86→  timeoutMs?: number;
    87→    87→}
    88→    88→
    89→    89→export interface ManhourLevelingJobData {
    90→    90→  depotId?: string;
    91→    91→  periodStart: string;
    92→    92→  periodEnd: string;
    93→    93→  strategies?: string[];
    94→    94→}
    95→    95→
    96→    96→export interface DriftMonitorJobData {
    97→    97→  baselineId: string;
    98→    98→  trainIds?: string[];
    99→    99→}
   100→   100→
   101→   101→export interface NotificationJobData {
   102→   102→  type: 'email' | 'webhook';
   103→   103→  template: string;
   104→   104→  recipients: string[];
   105→   105→  data: Record<string, unknown>;
   106→   106→  priority?: 'high' | 'normal' | 'low';
   107→   107→}
   108→   108→
   109→   109→export interface ReportJobData {
   110→   110→  type: 'pm_schedule' | 'fleet_status' | 'drift_report' | 'tco_projection';
   111→   111→  format: 'pdf' | 'excel';
   112→   112→  filters?: Record<string, unknown>;
   113→   113→  requestedBy: string;
   114→   114→}
   115→   115→
   116→   116→export interface MaximoSyncJobData {
   117→   117→  /** Sync operation: push, pull, full (both), or polling (scheduled pull) */
   118→   118→  operation: 'push' | 'pull' | 'full' | 'polling';
   119→   119→  /** Optional: specific PM schedule IDs to sync (push only) */
   120→   120→  pmScheduleIds?: string[];
   121→   121→  /** Optional: depot ID to limit sync scope */
   122→   122→  depotId?: string;
   123→   123→  /** Force sync even if recently synced */
   124→   124→  force?: boolean;
   125→   125→  /** Conflict resolution strategy (must match ConflictResolution type from maximo-sync service) */
   126→   126→  conflictResolution?: 'USE_MMS' | 'USE_MAXIMO';
   127→   127→  /** Polling-specific: triggered by webhook timeout fallback */
   128→   128→  isPollingFallback?: boolean;
   129→   129→  /** Polling-specific: modified since timestamp for incremental queries */
   130→   130→  modifiedSince?: string;
   131→   131→  /** Polling-specific: enable deduplication against recent webhooks */
   132→   132→  deduplicateWithWebhooks?: boolean;
   133→   133→}
   134→   134→
   135→   135→export type JobData =
   136→   136→  | IngestionJobData
   137→   137→  | TacticalSchedulerJobData
   138→   138→  | StrategicPlannerJobData
   139→   139→  | OptimizerJobData
   140→   140→  | ManhourLevelingJobData
   141→   141→  | DriftMonitorJobData
   142→   142→  | NotificationJobData
   143→   143→  | ReportJobData
   144→   144→  | MaximoSyncJobData;
   145→   145→
   146→   146→// =============================================================================
   147→   147→// Default Job Options
   148→   148→// =============================================================================
   149→   149→
   150→   150→const DEFAULT_JOB_OPTIONS: JobsOptions = {
   151→   151→  attempts: 3,
   152→   152→  backoff: {
   153→   153→    type: 'exponential',
   154→   154→    delay: 1000,
   155→   155→  },
   156→   156→  removeOnComplete: {
   157→   157→    age: 24 * 3600,
   158→   158→    count: 1000,
   159→   159→  },
   160→   160→  removeOnFail: {
   161→   161→    age: 7 * 24 * 3600,
   162→   162→  },
   163→   163→};
   164→   164→
   165→   165→// =============================================================================
   166→   166→// Queue Factory
   167→   167→// =============================================================================
   168→   168→
   169→   169→// eslint-disable-next-line @typescript-eslint/no-explicit-any
   170→   170→const queues: Map<QueueName, Queue<any>> = new Map();
   171→   171→const queueEvents: Map<QueueName, QueueEvents> = new Map();
   172→   172→
   173→   173→/**
   174→   174→ * Get or create a queue instance
   175→   175→ */
   176→   176→export function getQueue(name: QueueName): Queue {
   177→   177→  if (!queues.has(name)) {
   178→   178→    const queue = new Queue(name, {
   179→   179→      connection: getRedisConfig(),
   180→   180→      defaultJobOptions: DEFAULT_JOB_OPTIONS,
   181→   181→    });
   182→   182→    queues.set(name, queue);
   183→   183→  }
   184→   184→  return queues.get(name)!;
   185→   185→}
   186→   186→
   187→   187→/**
   188→   188→ * Get queue events for monitoring
   189→   189→ */
   190→   190→export function getQueueEvents(name: QueueName): QueueEvents {
   191→   191→  if (!queueEvents.has(name)) {
   192→   192→    const events = new QueueEvents(name, { connection: getRedisConfig() });
   193→   193→    queueEvents.set(name, events);
   194→   194→  }
   195→   195→  return queueEvents.get(name)!;
   196→   196→}
   197→   197→
   198→   198→// =============================================================================
   199→   199→// Worker Factory
   200→   200→// =============================================================================
   201→   201→
   202→   202→export interface JobContext<T = unknown> {
   203→   203→  id?: string;
   204→   204→  name: string;
   205→   205→  data: T;
   206→   206→}
   207→   207→
   208→   208→/**
   209→   209→ * Create a worker for processing jobs
   210→   210→ */
   211→   211→export function createWorker<T = JobData>(
   212→   212→  name: QueueName,
   213→   213→  processor: (job: JobContext<T>) => Promise<unknown>,
   214→   214→  options?: Partial<WorkerOptions>
   215→   215→): Worker {
   216→   216→  const workerOptions: WorkerOptions = {
   217→   217→    connection: getRedisConfig(),
   218→   218→    concurrency: 1,
   219→   219→    ...options,
   220→   220→  };
   221→   221→
   222→   222→  return new Worker(
   223→   223→    name,
   224→   224→    async (job) => {
   225→   225→      return processor({
   226→   226→        id: job.id,
   227→   227→        name: job.name,
   228→   228→        data: job.data as T,
   229→   229→      });
   230→   230→    },
   231→   231→    workerOptions
   232→   232→  );
   233→   233→}
   234→   234→
   235→   235→// =============================================================================
   236→   236→// Job Utilities
   237→   237→// =============================================================================
   238→   238→
   239→   239→/**
   240→   240→ * Add a job to a queue
   241→   241→ */
   242→   242→export async function addJob<T = JobData>(
   243→   243→  queueName: QueueName,
   244→   244→  jobName: string,
   245→   245→  data: T,
   246→   246→  options?: Partial<JobsOptions>
   247→   247→): Promise<{ id: string }> {
   248→   248→  const queue = getQueue(queueName);
   249→   249→  const job = await queue.add(jobName, data, options);
   250→   250→  return { id: job.id! };
   251→   251→}
   252→   252→
   253→   253→/**
   254→   254→ * Add multiple jobs to a queue
   255→   255→ */
   256→   256→export async function addBulkJobs<T = JobData>(
   257→   257→  queueName: QueueName,
   258→   258→  jobs: Array<{ name: string; data: T; opts?: Partial<JobsOptions> }>
   259→   259→): Promise<Array<{ id: string }>> {
   260→   260→  const queue = getQueue(queueName);
   261→   261→  const results = await queue.addBulk(jobs);
   262→   262→  return results.map((job) => ({ id: job.id! }));
   263→   263→}
   264→   264→
   265→   265→/**
   266→   266→ * Get job by ID
   267→   267→ */
   268→   268→export async function getJob<T = JobData>(
   269→   269→  queueName: QueueName,
   270→   270→  jobId: string
   271→   271→): Promise<{ id: string; data: T; status: string } | null> {
   272→   272→  const queue = getQueue(queueName);
   273→   273→  const job = await queue.getJob(jobId);
   274→   274→  if (!job) return null;
   275→   275→
   276→   276→  const state = await job.getState();
   277→   277→  return {
   278→   278→    id: job.id!,
   279→   279→    data: job.data as T,
   280→   280→    status: state,
   281→   281→  };
   282→   282→}
   283→   283→
   284→   284→/**
   285→   285→ * Get queue statistics
   286→   286→ */
   287→   287→export async function getQueueStats(queueName: QueueName): Promise<{
   288→   288→  waiting: number;
   289→   289→  active: number;
   290→   290→  completed: number;
   291→   291→  failed: number;
   292→   292→  delayed: number;
   293→   293→}> {
   294→   294→  const queue = getQueue(queueName);
   295→   295→  const [waiting, active, completed, failed, delayed] = await Promise.all([
   296→   296→    queue.getWaitingCount(),
   297→   297→    queue.getActiveCount(),
   298→   298→    queue.getCompletedCount(),
   299→   299→    queue.getFailedCount(),
   300→   300→    queue.getDelayedCount(),
   301→   301→  ]);
   302→   302→  return { waiting, active, completed, failed, delayed };
   303→   303→}
   304→   304→
   305→   305→// =============================================================================
   306→   306→// Cleanup
   307→   307→// =============================================================================
   308→   308→
   309→   309→/**
   310→   310→ * Close all queue connections
   311→   311→ */
   312→   312→export async function closeAllQueues(): Promise<void> {
   313→   313→  const closePromises: Promise<void>[] = [];
   314→   314→
   315→   315→  for (const queue of queues.values()) {
   316→   316→    closePromises.push(queue.close());
   317→   317→  }
   318→   318→
   319→   319→  for (const events of queueEvents.values()) {
   320→   320→    closePromises.push(events.close());
   321→   321→  }
   322→   322→
   323→   323→  await Promise.all(closePromises);
   324→   324→  queues.clear();
   325→   325→  queueEvents.clear();
   326→   326→}
   327→   327→
   328→   328→// =============================================================================
   329→   329→// Progress Streaming
   330→   330→// =============================================================================
   331→   331→
   332→   332→export interface JobProgress {
   333→   333→  percent: number;
   334→   334→  stage?: string;
   335→   335→  message?: string;
   336→   336→  details?: Record<string, unknown>;
   337→   337→}
   338→   338→
   339→   339→/**
   340→   340→ * Stream job progress updates via callback
   341→   341→ */
   342→   342→export function streamJobProgress(
   343→   343→  queueName: QueueName,
   344→   344→  jobId: string,
   345→   345→  onProgress: (progress: unknown) => void,
   346→   346→  onComplete: (result: unknown) => void,
   347→   347→  onError: (error: Error) => void
   348→   348→): () => void {
   349→   349→  const events = getQueueEvents(queueName);
   350→   350→
   351→   351→  const progressHandler = (args: { jobId: string; data: unknown }) => {
   352→   352→    if (args.jobId === jobId) {
   353→   353→      onProgress(args.data);
   354→   354→    }
   355→   355→  };
   356→   356→
   357→   357→  const completedHandler = (args: { jobId: string; returnvalue: unknown }) => {
   358→   358→    if (args.jobId === jobId) {
   359→   359→      onComplete(args.returnvalue);
   360→   360→      cleanup();
   361→   361→    }
   362→   362→  };
   363→   363→
   364→   364→  const failedHandler = (args: { jobId: string; failedReason: string }) => {
   365→   365→    if (args.jobId === jobId) {
   366→   366→      onError(new Error(args.failedReason));
   367→   367→      cleanup();
   368→   368→    }
   369→   369→  };
   370→   370→
   371→   371→  events.on('progress', progressHandler);
   372→   372→  events.on('completed', completedHandler);
   373→   373→  events.on('failed', failedHandler);
   374→   374→
   375→   375→  const cleanup = () => {
   376→   376→    events.off('progress', progressHandler);
   377→   377→    events.off('completed', completedHandler);
   378→   378→    events.off('failed', failedHandler);
   379→   379→  };
   380→   380→
   381→   381→  return cleanup;
   382→   382→}
