     1→     1→/**
     2→     2→ * MMS OpenTelemetry Tracing Configuration
     3→     3→ *
     4→     4→ * Provides distributed tracing for all MMS services.
     5→     5→ * Integrates with Pino logging for correlated trace context.
     6→     6→ *
     7→     7→ * Features:
     8→     8→ * - Automatic span context propagation
     9→     9→ * - Span attribute helpers for domain-specific data
    10→    10→ * - Integration with existing Pino logger
    11→    11→ * - Configurable exporters (OTLP, Jaeger, Console)
    12→    12→ *
    13→    13→ * @see specs/004-domain-services.md - All services emit OpenTelemetry traces
    14→    14→ */
    15→    15→
    16→    16→import {
    17→    17→  trace,
    18→    18→  context,
    19→    19→  SpanStatusCode,
    20→    20→  SpanKind,
    21→    21→  type Span,
    22→    22→  type Tracer,
    23→    23→  type Context,
    24→    24→  type SpanOptions,
    25→    25→  type Attributes,
    26→    26→} from '@opentelemetry/api';
    27→    27→import {
    28→    28→  SEMRESATTRS_SERVICE_NAME,
    29→    29→  SEMRESATTRS_SERVICE_VERSION,
    30→    30→  SEMRESATTRS_DEPLOYMENT_ENVIRONMENT,
    31→    31→} from '@opentelemetry/semantic-conventions';
    32→    32→
    33→    33→const SERVICE_NAME = process.env['SERVICE_NAME'] ?? 'mms';
    34→    34→const SERVICE_VERSION = process.env['SERVICE_VERSION'] ?? '0.1.0';
