     1→     1→/**
     2→     2→ * MMS Date/Time Utilities
     3→     3→ *
     4→     4→ * Timezone-aware date utilities for PM scheduling and compliance windows.
     5→     5→ * All operations use Asia/Hong_Kong timezone as the default depot timezone.
     6→     6→ *
     7→     7→ * @see specs/004-backend-specification.md Section 4.4
     8→     8→ */
     9→     9→
    10→    10→import {
    11→    11→  addDays,
    12→    12→  addMonths,
    13→    13→  addWeeks,
    14→    14→  differenceInDays,
    15→    15→  endOfDay,
    16→    16→  endOfWeek,
    17→    17→  format,
    18→    18→  isAfter,
    19→    19→  isBefore,
    20→    20→  isValid,
    21→    21→  isWithinInterval,
    22→    22→  parseISO,
    23→    23→  startOfDay,
    24→    24→  startOfWeek,
    25→    25→} from 'date-fns';
    26→    26→import { formatInTimeZone, toZonedTime, fromZonedTime } from 'date-fns-tz';
    27→    27→
    28→    28→/** Default timezone for MMS operations */
    29→    29→export const DEFAULT_TIMEZONE = 'Asia/Hong_Kong';
    30→    30→
    31→    31→/** PM compliance window tolerance (±10%) */
    32→    32→export const COMPLIANCE_TOLERANCE_PCT = 0.10;
    33→    33→
    34→    34→/** Day type for service demand */
    35→    35→export type DayType = 'WEEKDAY' | 'SATURDAY' | 'SUNDAY' | 'HOLIDAY';
    36→    36→
    37→    37→// =============================================================================
    38→    38→// Timezone Utilities
    39→    39→// =============================================================================
    40→    40→
    41→    41→/**
    42→    42→ * Convert UTC date to local timezone
    43→    43→ */
    44→    44→export function toLocalTime(date: Date, timezone: string = DEFAULT_TIMEZONE): Date {
    45→    45→  return toZonedTime(date, timezone);
    46→    46→}
    47→    47→
    48→    48→/**
    49→    49→ * Convert local timezone to UTC
    50→    50→ */
    51→    51→export function toUtc(date: Date, timezone: string = DEFAULT_TIMEZONE): Date {
    52→    52→  return fromZonedTime(date, timezone);
    53→    53→}
    54→    54→
    55→    55→/**
    56→    56→ * Format date in specific timezone
    57→    57→ */
    58→    58→export function formatInTimezone(
    59→    59→  date: Date,
    60→    60→  formatStr: string,
    61→    61→  timezone: string = DEFAULT_TIMEZONE
    62→    62→): string {
    63→    63→  return formatInTimeZone(date, timezone, formatStr);
    64→    64→}
    65→    65→
    66→    66→/**
    67→    67→ * Get current date in timezone (start of day)
    68→    68→ */
    69→    69→export function getTodayInTimezone(timezone: string = DEFAULT_TIMEZONE): Date {
    70→    70→  const now = new Date();
    71→    71→  const zoned = toZonedTime(now, timezone);
    72→    72→  return startOfDay(zoned);
    73→    73→}
    74→    74→
    75→    75→// =============================================================================
    76→    76→// Compliance Window Utilities
    77→    77→// =============================================================================
    78→    78→
    79→    79→export interface ComplianceWindow {
    80→    80→  start: Date;
    81→    81→  end: Date;
    82→    82→  targetDate: Date;
    83→    83→  isValid: boolean;
    84→    84→}
    85→    85→
    86→    86→/**
    87→    87→ * Calculate compliance window for a PM
    88→    88→ *
    89→    89→ * The compliance window is calculated based on the PM interval (km or months)
    90→    90→ * with a ±10% tolerance.
    91→    91→ *
    92→    92→ * @param lastPmDate - Date of last PM completion
    93→    93→ * @param intervalMonths - PM interval in months (e.g., 12 for annual)
    94→    94→ * @param intervalKm - PM interval in km (e.g., 180000)
    95→    95→ * @param currentMileageKm - Current train mileage
    96→    96→ * @param dailyKmRate - Expected daily mileage accrual
    97→    97→ */
    98→    98→export function calculateComplianceWindow(options: {
    99→    99→  lastPmDate: Date;
   100→   100→  intervalMonths?: number;
   101→   101→  intervalKm?: number;
   102→   102→  currentMileageKm?: number;
   103→   103→  dailyKmRate?: number;
   104→   104→  lastPmMileageKm?: number;
   105→   105→}): ComplianceWindow {
   106→   106→  const {
   107→   107→    lastPmDate,
   108→   108→    intervalMonths,
   109→   109→    intervalKm,
   110→   110→    currentMileageKm,
   111→   111→    dailyKmRate = 280, // Default: 280 km/day
   112→   112→    lastPmMileageKm = 0,
   113→   113→  } = options;
   114→   114→
   115→   115→  let targetDate: Date;
   116→   116→  let windowStart: Date;
   117→   117→  let windowEnd: Date;
   118→   118→
   119→   119→  // Time-based trigger
   120→   120→  if (intervalMonths) {
   121→   121→    targetDate = addMonths(lastPmDate, intervalMonths);
   122→   122→    const toleranceDays = Math.floor(intervalMonths * 30 * COMPLIANCE_TOLERANCE_PCT);
   123→   123→    windowStart = addDays(targetDate, -toleranceDays);
   124→   124→    windowEnd = addDays(targetDate, toleranceDays);
   125→   125→  }
   126→   126→  // Mileage-based trigger
   127→   127→  else if (intervalKm && currentMileageKm !== undefined) {
   128→   128→    const targetMileage = lastPmMileageKm + intervalKm;
   129→   129→    const remainingKm = targetMileage - currentMileageKm;
   130→   130→    const daysToTarget = Math.ceil(remainingKm / dailyKmRate);
   131→   131→
   132→   132→    targetDate = addDays(new Date(), daysToTarget);
   133→   133→
   134→   134→    const toleranceKm = intervalKm * COMPLIANCE_TOLERANCE_PCT;
   135→   135→    const toleranceDays = Math.ceil(toleranceKm / dailyKmRate);
   136→   136→
   137→   137→    windowStart = addDays(targetDate, -toleranceDays);
   138→   138→    windowEnd = addDays(targetDate, toleranceDays);
   139→   139→  } else {
   140→   140→    // Fallback: use last PM date + 1 year
   141→   141→    targetDate = addMonths(lastPmDate, 12);
   142→   142→    windowStart = addMonths(targetDate, -1);
   143→   143→    windowEnd = addMonths(targetDate, 1);
   144→   144→  }
   145→   145→
   146→   146→  return {
   147→   147→    start: windowStart,
   148→   148→    end: windowEnd,
   149→   149→    targetDate,
   150→   150→    isValid: true,
   151→   151→  };
   152→   152→}
   153→   153→
   154→   154→/**
   155→   155→ * Check if a date falls within a compliance window
   156→   156→ */
   157→   157→export function isWithinComplianceWindow(date: Date, window: ComplianceWindow): boolean {
   158→   158→  return isWithinInterval(date, { start: window.start, end: window.end });
   159→   159→}
   160→   160→
   161→   161→/**
   162→   162→ * Check if a PM is overdue (past compliance window)
   163→   163→ */
   164→   164→export function isPmOverdue(window: ComplianceWindow, currentDate: Date = new Date()): boolean {
   165→   165→  return isAfter(currentDate, window.end);
   166→   166→}
   167→   167→
   168→   168→/**
   169→   169→ * Check if a PM is upcoming (within compliance window or before)
   170→   170→ */
   171→   171→export function isPmUpcoming(window: ComplianceWindow, currentDate: Date = new Date()): boolean {
   172→   172→  return isBefore(currentDate, window.start);
   173→   173→}
   174→   174→
   175→   175→/**
   176→   176→ * Get days until PM compliance window ends
   177→   177→ */
   178→   178→export function getDaysToDeadline(window: ComplianceWindow, currentDate: Date = new Date()): number {
   179→   179→  return differenceInDays(window.end, currentDate);
   180→   180→}
   181→   181→
   182→   182→// =============================================================================
   183→   183→// PM Hierarchy Utilities
   184→   184→// =============================================================================
   185→   185→
   186→   186→/** PM code hierarchy (higher PMs satisfy lower PMs) */
   187→   187→export const PM_HIERARCHY: Record<string, string[]> = {
   188→   188→  'OVERHAUL': ['C4', 'C3', 'C2', 'C1'],
   189→   189→  'C4': ['C3', 'C2', 'C1'],
   190→   190→  'C3': ['C2', 'C1'],
   191→   191→  'C2': ['C1'],
   192→   192→  'C1': [],
   193→   193→};
   194→   194→
   195→   195→/**
   196→   196→ * Get list of PM codes that a given PM satisfies
   197→   197→ */
   198→   198→export function getSatisfiedPmCodes(pmCode: string): string[] {
   199→   199→  return PM_HIERARCHY[pmCode] ?? [];
   200→   200→}
   201→   201→
   202→   202→/**
   203→   203→ * Check if completing PM A satisfies PM B
   204→   204→ */
   205→   205→export function pmSatisfies(pmCodeA: string, pmCodeB: string): boolean {
   206→   206→  const satisfies = PM_HIERARCHY[pmCodeA];
   207→   207→  return satisfies?.includes(pmCodeB) ?? false;
   208→   208→}
   209→   209→
   210→   210→// =============================================================================
   211→   211→// Mileage Projection Utilities
   212→   212→// =============================================================================
   213→   213→
   214→   214→export interface MileageProjection {
   215→   215→  date: Date;
   216→   216→  projectedMileageKm: number;
   217→   217→  dailyRateKm: number;
   218→   218→  confidence: 'HIGH' | 'MEDIUM' | 'LOW' | 'ESTIMATED';
   219→   219→}
   220→   220→
   221→   221→/**
   222→   222→ * Project mileage at a future date
   223→   223→ *
   224→   224→ * @param currentMileageKm - Current train mileage
   225→   225→ * @param targetDate - Date to project to
   226→   226→ * @param dailyRateKm - Daily mileage accrual rate
   227→   227→ * @param currentDate - Starting date (defaults to today)
   228→   228→ */
   229→   229→export function projectMileage(
   230→   230→  currentMileageKm: number,
   231→   231→  targetDate: Date,
   232→   232→  dailyRateKm: number = 280,
   233→   233→  currentDate: Date = new Date()
   234→   234→): MileageProjection {
   235→   235→  const daysDiff = differenceInDays(targetDate, currentDate);
   236→   236→  const projectedKm = currentMileageKm + daysDiff * dailyRateKm;
   237→   237→
   238→   238→  // Confidence decreases with projection distance
   239→   239→  let confidence: MileageProjection['confidence'];
   240→   240→  if (daysDiff <= 30) {
   241→   241→    confidence = 'HIGH';
   242→   242→  } else if (daysDiff <= 90) {
   243→   243→    confidence = 'MEDIUM';
   244→   244→  } else if (daysDiff <= 365) {
   245→   245→    confidence = 'LOW';
   246→   246→  } else {
   247→   247→    confidence = 'ESTIMATED';
   248→   248→  }
   249→   249→
   250→   250→  return {
   251→   251→    date: targetDate,
   252→   252→    projectedMileageKm: Math.round(projectedKm),
   253→   253→    dailyRateKm,
   254→   254→    confidence,
   255→   255→  };
   256→   256→}
   257→   257→
   258→   258→/**
   259→   259→ * Calculate date when train will reach target mileage
   260→   260→ */
   261→   261→export function projectDateForMileage(
   262→   262→  currentMileageKm: number,
   263→   263→  targetMileageKm: number,
   264→   264→  dailyRateKm: number = 280,
   265→   265→  currentDate: Date = new Date()
   266→   266→): Date {
   267→   267→  const remainingKm = targetMileageKm - currentMileageKm;
   268→   268→  const daysToTarget = Math.ceil(remainingKm / dailyRateKm);
   269→   269→  return addDays(currentDate, daysToTarget);
   270→   270→}
   271→   271→
   272→   272→// =============================================================================
   273→   273→// Week/Period Utilities
   274→   274→// =============================================================================
   275→   275→
   276→   276→/**
   277→   277→ * Get week boundaries (Monday-Sunday)
   278→   278→ */
   279→   279→export function getWeekBoundaries(date: Date): { start: Date; end: Date } {
   280→   280→  return {
   281→   281→    start: startOfWeek(date, { weekStartsOn: 1 }), // Monday
   282→   282→    end: endOfWeek(date, { weekStartsOn: 1 }), // Sunday
   283→   283→  };
   284→   284→}
   285→   285→
   286→   286→/**
   287→   287→ * Get day type for a given date
   288→   288→ */
   289→   289→export function getDayType(date: Date): DayType {
   290→   290→  const dayOfWeek = date.getDay();
   291→   291→  if (dayOfWeek === 0) return 'SUNDAY';
   292→   292→  if (dayOfWeek === 6) return 'SATURDAY';
   293→   293→  return 'WEEKDAY';
   294→   294→  // Note: Holiday detection requires external calendar data
   295→   295→}
   296→   296→
   297→   297→/**
   298→   298→ * Generate date range array
   299→   299→ */
   300→   300→export function generateDateRange(start: Date, end: Date): Date[] {
   301→   301→  const dates: Date[] = [];
   302→   302→  let current = startOfDay(start);
   303→   303→  const endDay = endOfDay(end);
   304→   304→
   305→   305→  while (isBefore(current, endDay) || current.getTime() === startOfDay(endDay).getTime()) {
   306→   306→    dates.push(current);
   307→   307→    current = addDays(current, 1);
   308→   308→  }
   309→   309→
   310→   310→  return dates;
   311→   311→}
   312→   312→
   313→   313→/**
   314→   314→ * Generate weekly periods for a date range
   315→   315→ */
   316→   316→export function generateWeeklyPeriods(
   317→   317→  start: Date,
   318→   318→  end: Date
   319→   319→): Array<{ start: Date; end: Date }> {
   320→   320→  const periods: Array<{ start: Date; end: Date }> = [];
   321→   321→  let current = startOfWeek(start, { weekStartsOn: 1 });
   322→   322→
   323→   323→  while (isBefore(current, end)) {
   324→   324→    periods.push({
   325→   325→      start: current,
   326→   326→      end: endOfWeek(current, { weekStartsOn: 1 }),
   327→   327→    });
   328→   328→    current = addWeeks(current, 1);
   329→   329→  }
   330→   330→
   331→   331→  return periods;
   332→   332→}
   333→   333→
   334→   334→// =============================================================================
   335→   335→// Parsing Utilities
   336→   336→// =============================================================================
   337→   337→
   338→   338→/**
   339→   339→ * Parse date string (YYYY-MM-DD format)
   340→   340→ */
   341→   341→export function parseDateString(dateStr: string): Date | null {
   342→   342→  const parsed = parseISO(dateStr);
   343→   343→  return isValid(parsed) ? parsed : null;
   344→   344→}
   345→   345→
   346→   346→/**
   347→   347→ * Format date for display
   348→   348→ */
   349→   349→export function formatDisplayDate(date: Date, formatStr: string = 'yyyy-MM-dd'): string {
   350→   350→  return format(date, formatStr);
   351→   351→}
   352→   352→
   353→   353→/**
   354→   354→ * Format date for API response
   355→   355→ */
   356→   356→export function formatIsoDate(date: Date): string {
   357→   357→  return date.toISOString();
   358→   358→}
   359→   359→
   360→   360→// =============================================================================
   361→   361→// Performance Utilities
   362→   362→// =============================================================================
   363→   363→
   364→   364→/**
   365→   365→ * Measure duration of an async operation
   366→   366→ */
   367→   367→export async function measureDuration<T>(
   368→   368→  operation: () => Promise<T>
   369→   369→): Promise<{ result: T; durationMs: number }> {
   370→   370→  const start = performance.now();
   371→   371→  const result = await operation();
   372→   372→  const durationMs = Math.round(performance.now() - start);
   373→   373→  return { result, durationMs };
   374→   374→}
   375→   375→
   376→   376→/**
   377→   377→ * Create a stopwatch for manual timing
   378→   378→ */
   379→   379→export function createStopwatch(): {
   380→   380→  start: () => void;
   381→   381→  stop: () => number;
   382→   382→  elapsed: () => number;
   383→   383→} {
   384→   384→  let startTime: number | null = null;
   385→   385→  let endTime: number | null = null;
   386→   386→
   387→   387→  return {
   388→   388→    start: () => {
   389→   389→      startTime = performance.now();
   390→   390→      endTime = null;
   391→   391→    },
   392→   392→    stop: () => {
   393→   393→      if (startTime === null) return 0;
   394→   394→      endTime = performance.now();
   395→   395→      return Math.round(endTime - startTime);
   396→   396→    },
   397→   397→    elapsed: () => {
   398→   398→      if (startTime === null) return 0;
   399→   399→      const end = endTime ?? performance.now();
   400→   400→      return Math.round(end - startTime);
   401→   401→    },
   402→   402→  };
   403→   403→}
