     1→     1→/**
     2→     2→ * MMS Resilience Utilities
     3→     3→ *
     4→     4→ * Provides retry and circuit breaker patterns for handling transient failures.
     5→     5→ * Critical for integration with external systems (Maximo, OCC) and for
     6→     6→ * maintaining service availability during infrastructure issues.
     7→     7→ *
     8→     8→ * @see specs/007-integration.md - External system integration patterns
     9→     9→ * @see specs/004-domain-services.md - Service reliability requirements
    10→    10→ */
    11→    11→
    12→    12→import { withSpan, addSpanEvent, SpanKind } from '../tracing';
    13→    13→import { TimeoutError, ExternalServiceError, ServiceUnavailableError } from '../errors';
    14→    14→import { logger } from '../logging/logger';
    15→    15→
    16→    16→// =============================================================================
    17→    17→// Retry Configuration & Implementation
    18→    18→// =============================================================================
    19→    19→
    20→    20→/**
    21→    21→ * Retry configuration options
    22→    22→ */
    23→    23→export interface RetryConfig {
    24→    24→  /** Maximum number of retry attempts */
    25→    25→  maxAttempts: number;
    26→    26→  /** Initial delay between retries (ms) */
    27→    27→  initialDelayMs: number;
    28→    28→  /** Maximum delay between retries (ms) */
    29→    29→  maxDelayMs: number;
    30→    30→  /** Backoff multiplier (e.g., 2 for exponential) */
    31→    31→  backoffMultiplier: number;
    32→    32→  /** Add random jitter to delays (prevents thundering herd) */
    33→    33→  jitter: boolean;
    34→    34→  /** Predicate to determine if an error is retryable */
    35→    35→  isRetryable?: (error: unknown) => boolean;
    36→    36→  /** Callback invoked before each retry */
    37→    37→  onRetry?: (error: unknown, attempt: number, delayMs: number) => void;
    38→    38→}
    39→    39→
    40→    40→/**
    41→    41→ * Default retry configuration
    42→    42→ * Suitable for most transient failure scenarios
    43→    43→ */
    44→    44→export const DEFAULT_RETRY_CONFIG: RetryConfig = {
    45→    45→  maxAttempts: 3,
    46→    46→  initialDelayMs: 1000,
    47→    47→  maxDelayMs: 30000,
    48→    48→  backoffMultiplier: 2,
    49→    49→  jitter: true,
    50→    50→  isRetryable: defaultIsRetryable,
    51→    51→};
    52→    52→
    53→    53→/**
    54→    54→ * Aggressive retry configuration
    55→    55→ * Use for critical operations that must succeed
    56→    56→ */
    57→    57→export const AGGRESSIVE_RETRY_CONFIG: RetryConfig = {
    58→    58→  maxAttempts: 5,
    59→    59→  initialDelayMs: 500,
    60→    60→  maxDelayMs: 60000,
    61→    61→  backoffMultiplier: 2,
    62→    62→  jitter: true,
    63→    63→  isRetryable: defaultIsRetryable,
    64→    64→};
    65→    65→
    66→    66→/**
    67→    67→ * Quick retry configuration
    68→    68→ * Use for fast operations where quick recovery is expected
    69→    69→ */
    70→    70→export const QUICK_RETRY_CONFIG: RetryConfig = {
    71→    71→  maxAttempts: 3,
    72→    72→  initialDelayMs: 100,
    73→    73→  maxDelayMs: 2000,
    74→    74→  backoffMultiplier: 2,
    75→    75→  jitter: true,
    76→    76→  isRetryable: defaultIsRetryable,
    77→    77→};
    78→    78→
    79→    79→/**
    80→    80→ * External service retry configuration
    81→    81→ * Use for Maximo, OCC, and other external integrations
    82→    82→ */
    83→    83→export const EXTERNAL_SERVICE_RETRY_CONFIG: RetryConfig = {
    84→    84→  maxAttempts: 5,
    85→    85→  initialDelayMs: 2000,
    86→    86→  maxDelayMs: 60000,
    87→    87→  backoffMultiplier: 2,
    88→    88→  jitter: true,
    89→    89→  isRetryable: (error) => {
    90→    90→    // Retry on network errors, timeouts, and 5xx responses
    91→    91→    if (error instanceof TimeoutError) return true;
    92→    92→    if (error instanceof ExternalServiceError) return true;
    93→    93→    if (error instanceof ServiceUnavailableError) return true;
    94→    94→
    95→    95→    // Check for fetch/network errors
    96→    96→    if (error instanceof Error) {
    97→    97→      const message = error.message.toLowerCase();
    98→    98→      return (
    99→    99→        message.includes('network') ||
   100→   100→        message.includes('timeout') ||
   101→   101→        message.includes('econnrefused') ||
   102→   102→        message.includes('econnreset') ||
   103→   103→        message.includes('socket hang up')
   104→   104→      );
   105→   105→    }
   106→   106→
   107→   107→    return false;
   108→   108→  },
   109→   109→};
   110→   110→
   111→   111→/**
   112→   112→ * Default function to determine if an error is retryable
   113→   113→ */
   114→   114→function defaultIsRetryable(error: unknown): boolean {
   115→   115→  // Don't retry validation errors or not found errors
   116→   116→  if (error instanceof Error) {
   117→   117→    const code = (error as Error & { code?: string }).code ?? '';
   118→   118→    const statusCode = (error as Error & { statusCode?: number }).statusCode ?? 0;
   119→   119→
   120→   120→    // Don't retry 4xx client errors (except 408 timeout, 429 rate limit)
   121→   121→    if (statusCode >= 400 && statusCode < 500 && statusCode !== 408 && statusCode !== 429) {
   122→   122→      return false;
   123→   123→    }
   124→   124→
   125→   125→    // Don't retry certain error codes
   126→   126→    if (code.startsWith('BUS_') || code.startsWith('AUTH_')) {
   127→   127→      return false;
   128→   128→    }
   129→   129→  }
   130→   130→
   131→   131→  return true;
   132→   132→}
   133→   133→
   134→   134→/**
   135→   135→ * Calculate delay for a given attempt with optional jitter
   136→   136→ */
   137→   137→function calculateDelay(attempt: number, config: RetryConfig): number {
   138→   138→  const exponentialDelay = config.initialDelayMs * Math.pow(config.backoffMultiplier, attempt - 1);
   139→   139→  let delay = Math.min(exponentialDelay, config.maxDelayMs);
   140→   140→
   141→   141→  if (config.jitter) {
   142→   142→    // Add ±25% jitter
   143→   143→    const jitterRange = delay * 0.25;
   144→   144→    delay = delay - jitterRange + Math.random() * jitterRange * 2;
   145→   145→  }
   146→   146→
   147→   147→  return Math.round(delay);
   148→   148→}
   149→   149→
   150→   150→/**
   151→   151→ * Sleep for a specified duration
   152→   152→ */
   153→   153→function sleep(ms: number): Promise<void> {
   154→   154→  return new Promise((resolve) => setTimeout(resolve, ms));
   155→   155→}
   156→   156→
   157→   157→/**
   158→   158→ * Execute a function with retry logic
   159→   159→ *
   160→   160→ * Uses exponential backoff with optional jitter to handle transient failures.
   161→   161→ * Integrates with OpenTelemetry tracing for observability.
   162→   162→ *
   163→   163→ * @example
   164→   164→ * ```typescript
   165→   165→ * const result = await withRetry(
   166→   166→ *   async () => {
   167→   167→ *     return await fetchFromMaximo('/api/workorders');
   168→   168→ *   },
   169→   169→ *   {
   170→   170→ *     maxAttempts: 5,
   171→   171→ *     initialDelayMs: 1000,
   172→   172→ *     isRetryable: (error) => error instanceof NetworkError
   173→   173→ *   },
   174→   174→ *   'fetchWorkOrders'
   175→   175→ * );
   176→   176→ * ```
   177→   177→ */
   178→   178→export async function withRetry<T>(
   179→   179→  fn: () => Promise<T>,
   180→   180→  config?: Partial<RetryConfig>,
   181→   181→  operationName?: string
   182→   182→): Promise<T> {
   183→   183→  const opts = { ...DEFAULT_RETRY_CONFIG, ...config };
   184→   184→  const name = operationName ?? 'retry';
   185→   185→
   186→   186→  return withSpan(
   187→   187→    `resilience.${name}`,
   188→   188→    async (span) => {
   189→   189→      span.setAttribute('retry.max_attempts', opts.maxAttempts);
   190→   190→      let lastError: unknown;
   191→   191→
   192→   192→      for (let attempt = 1; attempt <= opts.maxAttempts; attempt++) {
   193→   193→        try {
   194→   194→          span.setAttribute('retry.current_attempt', attempt);
   195→   195→          addSpanEvent('retry.attempt', { attempt });
   196→   196→
   197→   197→          const result = await fn();
   198→   198→
   199→   199→          if (attempt > 1) {
   200→   200→            addSpanEvent('retry.success', { attempt, totalAttempts: attempt });
   201→   201→          }
   202→   202→
   203→   203→          return result;
   204→   204→        } catch (error) {
   205→   205→          lastError = error;
   206→   206→
   207→   207→          // Check if we should retry
   208→   208→          const shouldRetry = attempt < opts.maxAttempts && (opts.isRetryable?.(error) ?? true);
   209→   209→
   210→   210→          if (!shouldRetry) {
   211→   211→            addSpanEvent('retry.exhausted', {
   212→   212→              attempt,
   213→   213→              error: error instanceof Error ? error.message : String(error),
   214→   214→              retryable: opts.isRetryable?.(error) ?? true,
   215→   215→            });
   216→   216→            throw error;
   217→   217→          }
   218→   218→
   219→   219→          // Calculate delay
   220→   220→          const delayMs = calculateDelay(attempt, opts);
   221→   221→
   222→   222→          addSpanEvent('retry.waiting', {
   223→   223→            attempt,
   224→   224→            delayMs,
   225→   225→            error: error instanceof Error ? error.message : String(error),
   226→   226→          });
   227→   227→
   228→   228→          // Invoke callback if provided
   229→   229→          opts.onRetry?.(error, attempt, delayMs);
   230→   230→
   231→   231→          logger.warn(
   232→   232→            {
   233→   233→              operation: name,
   234→   234→              attempt,
   235→   235→              nextAttempt: attempt + 1,
   236→   236→              delayMs,
   237→   237→              error: error instanceof Error ? error.message : String(error),
   238→   238→            },
   239→   239→            `Retry attempt ${attempt}/${opts.maxAttempts} failed, waiting ${delayMs}ms`
   240→   240→          );
   241→   241→
   242→   242→          await sleep(delayMs);
   243→   243→        }
   244→   244→      }
   245→   245→
   246→   246→      // Should never reach here, but TypeScript needs this
   247→   247→      throw lastError;
   248→   248→    },
   249→   249→    { kind: SpanKind.INTERNAL }
   250→   250→  );
   251→   251→}
   252→   252→
   253→   253→// =============================================================================
   254→   254→// Circuit Breaker Implementation
   255→   255→// =============================================================================
   256→   256→
   257→   257→/**
   258→   258→ * Circuit breaker states
   259→   259→ */
   260→   260→export type CircuitState = 'CLOSED' | 'OPEN' | 'HALF_OPEN';
   261→   261→
   262→   262→/**
   263→   263→ * Circuit breaker configuration
   264→   264→ */
   265→   265→export interface CircuitBreakerConfig {
   266→   266→  /** Number of failures before opening the circuit */
   267→   267→  failureThreshold: number;
   268→   268→  /** Number of successes in half-open state to close circuit */
   269→   269→  successThreshold: number;
   270→   270→  /** Time to wait before transitioning from OPEN to HALF_OPEN (ms) */
   271→   271→  resetTimeoutMs: number;
   272→   272→  /** Function to determine if an error counts as a failure */
   273→   273→  isFailure?: (error: unknown) => boolean;
   274→   274→  /** Callback when circuit state changes */
   275→   275→  onStateChange?: (from: CircuitState, to: CircuitState) => void;
   276→   276→}
   277→   277→
   278→   278→/**
   279→   279→ * Default circuit breaker configuration
   280→   280→ */
   281→   281→export const DEFAULT_CIRCUIT_BREAKER_CONFIG: CircuitBreakerConfig = {
   282→   282→  failureThreshold: 5,
   283→   283→  successThreshold: 3,
   284→   284→  resetTimeoutMs: 30000,
   285→   285→  isFailure: () => true,
   286→   286→};
   287→   287→
   288→   288→/**
   289→   289→ * Circuit breaker metrics
   290→   290→ */
   291→   291→export interface CircuitBreakerMetrics {
   292→   292→  state: CircuitState;
   293→   293→  failures: number;
   294→   294→  successes: number;
   295→   295→  lastFailureTime: Date | null;
   296→   296→  lastSuccessTime: Date | null;
   297→   297→  totalRequests: number;
   298→   298→  totalFailures: number;
   299→   299→  totalSuccesses: number;
   300→   300→}
   301→   301→
   302→   302→/**
   303→   303→ * Circuit Breaker implementation
   304→   304→ *
   305→   305→ * Prevents cascading failures by stopping requests to a failing service.
   306→   306→ * Implements the standard circuit breaker pattern:
   307→   307→ * - CLOSED: Normal operation, requests flow through
   308→   308→ * - OPEN: Failures exceeded threshold, requests fail fast
   309→   309→ * - HALF_OPEN: Testing if service has recovered
   310→   310→ *
   311→   311→ * @example
   312→   312→ * ```typescript
   313→   313→ * const maximoBreaker = new CircuitBreaker({
   314→   314→ *   failureThreshold: 5,
   315→   315→ *   resetTimeoutMs: 30000,
   316→   316→ *   onStateChange: (from, to) => {
   317→   317→ *     logger.warn({ from, to }, 'Maximo circuit breaker state changed');
   318→   318→ *   }
   319→   319→ * }, 'maximo');
   320→   320→ *
   321→   321→ * // In service
   322→   322→ * const result = await maximoBreaker.execute(
   323→   323→ *   async () => fetchFromMaximo('/api/workorders')
   324→   324→ * );
   325→   325→ * ```
   326→   326→ */
   327→   327→export class CircuitBreaker {
   328→   328→  private state: CircuitState = 'CLOSED';
   329→   329→  private failures = 0;
   330→   330→  private successes = 0;
   331→   331→  private lastFailureTime: Date | null = null;
   332→   332→  private lastSuccessTime: Date | null = null;
   333→   333→  private totalRequests = 0;
   334→   334→  private totalFailures = 0;
   335→   335→  private totalSuccesses = 0;
   336→   336→  private readonly config: CircuitBreakerConfig;
   337→   337→  private readonly name: string;
   338→   338→  private readonly log: typeof logger;
   339→   339→
   340→   340→  constructor(config: Partial<CircuitBreakerConfig> = {}, name = 'default') {
   341→   341→    this.config = { ...DEFAULT_CIRCUIT_BREAKER_CONFIG, ...config };
   342→   342→    this.name = name;
   343→   343→    this.log = logger.child({ circuitBreaker: name });
   344→   344→  }
   345→   345→
   346→   346→  /**
   347→   347→   * Execute a function through the circuit breaker
   348→   348→   */
   349→   349→  async execute<T>(fn: () => Promise<T>): Promise<T> {
   350→   350→    return withSpan(
   351→   351→      `circuitBreaker.${this.name}`,
   352→   352→      async (span) => {
   353→   353→        span.setAttribute('circuit_breaker.name', this.name);
   354→   354→        span.setAttribute('circuit_breaker.state', this.state);
   355→   355→
   356→   356→        this.totalRequests++;
   357→   357→
   358→   358→        // Check if circuit should transition from OPEN to HALF_OPEN
   359→   359→        this.checkResetTimeout();
   360→   360→
   361→   361→        // If circuit is OPEN, fail fast
   362→   362→        if (this.state === 'OPEN') {
   363→   363→          addSpanEvent('circuit_breaker.rejected', { state: this.state });
   364→   364→          throw new ServiceUnavailableError(
   365→   365→            `Circuit breaker ${this.name} is OPEN. Service unavailable.`,
   366→   366→            { retryAfter: Math.ceil(this.config.resetTimeoutMs / 1000) }
   367→   367→          );
   368→   368→        }
   369→   369→
   370→   370→        try {
   371→   371→          const result = await fn();
   372→   372→          this.recordSuccess();
   373→   373→          addSpanEvent('circuit_breaker.success', { state: this.state });
   374→   374→          return result;
   375→   375→        } catch (error) {
   376→   376→          if (this.config.isFailure?.(error) ?? true) {
   377→   377→            this.recordFailure();
   378→   378→            addSpanEvent('circuit_breaker.failure', {
   379→   379→              state: this.state,
   380→   380→              failures: this.failures,
   381→   381→            });
   382→   382→          }
   383→   383→          throw error;
   384→   384→        }
   385→   385→      },
   386→   386→      { kind: SpanKind.INTERNAL }
   387→   387→    );
   388→   388→  }
   389→   389→
   390→   390→  /**
   391→   391→   * Check if the reset timeout has elapsed and transition to HALF_OPEN
   392→   392→   */
   393→   393→  private checkResetTimeout(): void {
   394→   394→    if (this.state !== 'OPEN' || !this.lastFailureTime) return;
   395→   395→
   396→   396→    const elapsed = Date.now() - this.lastFailureTime.getTime();
   397→   397→    if (elapsed >= this.config.resetTimeoutMs) {
   398→   398→      this.transition('HALF_OPEN');
   399→   399→    }
   400→   400→  }
   401→   401→
   402→   402→  /**
   403→   403→   * Record a successful execution
   404→   404→   */
   405→   405→  private recordSuccess(): void {
   406→   406→    this.successes++;
   407→   407→    this.totalSuccesses++;
   408→   408→    this.lastSuccessTime = new Date();
   409→   409→
   410→   410→    if (this.state === 'HALF_OPEN') {
   411→   411→      if (this.successes >= this.config.successThreshold) {
   412→   412→        this.transition('CLOSED');
   413→   413→      }
   414→   414→    } else if (this.state === 'CLOSED') {
   415→   415→      // Reset failure count on success in CLOSED state
   416→   416→      this.failures = 0;
   417→   417→    }
   418→   418→  }
   419→   419→
   420→   420→  /**
   421→   421→   * Record a failed execution
   422→   422→   */
   423→   423→  private recordFailure(): void {
   424→   424→    this.failures++;
   425→   425→    this.totalFailures++;
   426→   426→    this.lastFailureTime = new Date();
   427→   427→    this.successes = 0; // Reset success count on failure
   428→   428→
   429→   429→    if (this.state === 'HALF_OPEN') {
   430→   430→      // Any failure in HALF_OPEN opens the circuit again
   431→   431→      this.transition('OPEN');
   432→   432→    } else if (this.state === 'CLOSED') {
   433→   433→      if (this.failures >= this.config.failureThreshold) {
   434→   434→        this.transition('OPEN');
   435→   435→      }
   436→   436→    }
   437→   437→  }
   438→   438→
   439→   439→  /**
   440→   440→   * Transition to a new state
   441→   441→   */
   442→   442→  private transition(to: CircuitState): void {
   443→   443→    const from = this.state;
   444→   444→    if (from === to) return;
   445→   445→
   446→   446→    this.log.info({ from, to }, `Circuit breaker transitioning: ${from} -> ${to}`);
   447→   447→
   448→   448→    this.state = to;
   449→   449→    this.failures = 0;
   450→   450→    this.successes = 0;
   451→   451→
   452→   452→    this.config.onStateChange?.(from, to);
   453→   453→  }
   454→   454→
   455→   455→  /**
   456→   456→   * Get current circuit breaker metrics
   457→   457→   */
   458→   458→  getMetrics(): CircuitBreakerMetrics {
   459→   459→    return {
   460→   460→      state: this.state,
   461→   461→      failures: this.failures,
   462→   462→      successes: this.successes,
   463→   463→      lastFailureTime: this.lastFailureTime,
   464→   464→      lastSuccessTime: this.lastSuccessTime,
   465→   465→      totalRequests: this.totalRequests,
   466→   466→      totalFailures: this.totalFailures,
   467→   467→      totalSuccesses: this.totalSuccesses,
   468→   468→    };
   469→   469→  }
   470→   470→
   471→   471→  /**
   472→   472→   * Get current state
   473→   473→   */
   474→   474→  getState(): CircuitState {
   475→   475→    this.checkResetTimeout();
   476→   476→    return this.state;
   477→   477→  }
   478→   478→
   479→   479→  /**
   480→   480→   * Manually reset the circuit breaker to CLOSED state
   481→   481→   * Use with caution - primarily for testing or manual intervention
   482→   482→   */
   483→   483→  reset(): void {
   484→   484→    this.log.warn('Circuit breaker manually reset');
   485→   485→    this.state = 'CLOSED';
   486→   486→    this.failures = 0;
   487→   487→    this.successes = 0;
   488→   488→  }
   489→   489→
   490→   490→  /**
   491→   491→   * Manually open the circuit
   492→   492→   * Use for graceful degradation scenarios
   493→   493→   */
   494→   494→  open(): void {
   495→   495→    this.log.warn('Circuit breaker manually opened');
   496→   496→    this.transition('OPEN');
   497→   497→    this.lastFailureTime = new Date();
   498→   498→  }
   499→   499→}
   500→   500→
   501→   501→// =============================================================================
   502→   502→// Combined Retry + Circuit Breaker
   503→   503→// =============================================================================
   504→   504→
   505→   505→/**
   506→   506→ * Execute a function with both retry logic and circuit breaker protection
   507→   507→ *
   508→   508→ * The circuit breaker wraps the retry logic, so if the circuit is open,
   509→   509→ * no retries will be attempted.
   510→   510→ *
   511→   511→ * @example
   512→   512→ * ```typescript
   513→   513→ * const result = await withResilience(
   514→   514→ *   async () => fetchFromMaximo('/api/workorders'),
   515→   515→ *   maximoCircuitBreaker,
   516→   516→ *   EXTERNAL_SERVICE_RETRY_CONFIG,
   517→   517→ *   'fetchWorkOrders'
   518→   518→ * );
   519→   519→ * ```
   520→   520→ */
   521→   521→export async function withResilience<T>(
   522→   522→  fn: () => Promise<T>,
   523→   523→  circuitBreaker: CircuitBreaker,
   524→   524→  retryConfig?: Partial<RetryConfig>,
   525→   525→  operationName?: string
   526→   526→): Promise<T> {
   527→   527→  return circuitBreaker.execute(async () => withRetry(fn, retryConfig, operationName));
   528→   528→}
   529→   529→
   530→   530→// =============================================================================
   531→   531→// Timeout Utility
   532→   532→// =============================================================================
   533→   533→
   534→   534→/**
   535→   535→ * Execute a function with a timeout
   536→   536→ *
   537→   537→ * @example
   538→   538→ * ```typescript
   539→   539→ * const result = await withTimeout(
   540→   540→ *   async () => slowOperation(),
   541→   541→ *   5000,
   542→   542→ *   'slowOperation'
   543→   543→ * );
   544→   544→ * ```
   545→   545→ */
   546→   546→export async function withTimeout<T>(
   547→   547→  fn: () => Promise<T>,
   548→   548→  timeoutMs: number,
   549→   549→  operationName?: string
   550→   550→): Promise<T> {
   551→   551→  const name = operationName ?? 'operation';
   552→   552→
   553→   553→  return new Promise((resolve, reject) => {
   554→   554→    const timer = setTimeout(() => {
   555→   555→      reject(
   556→   556→        new TimeoutError(`Operation ${name} timed out after ${timeoutMs}ms`, {
   557→   557→          operation: name,
   558→   558→          timeoutMs,
   559→   559→        })
   560→   560→      );
   561→   561→    }, timeoutMs);
   562→   562→
   563→   563→    fn()
   564→   564→      .then((result) => {
   565→   565→        clearTimeout(timer);
   566→   566→        resolve(result);
   567→   567→      })
   568→   568→      .catch((error) => {
   569→   569→        clearTimeout(timer);
   570→   570→        reject(error);
   571→   571→      });
   572→   572→  });
   573→   573→}
