     1→     1→/**
     2→     2→ * MMS Transaction Utilities
     3→     3→ *
     4→     4→ * Enhanced transaction helpers for reliable database operations.
     5→     5→ * Provides automatic rollback, nested transaction support, and tracing integration.
     6→     6→ *
     7→     7→ * @see specs/004-domain-services.md
     8→     8→ */
     9→     9→
    10→    10→import { db, type Transaction, type Database } from '../db/connection';
    11→    11→import { withSpan, addSpanEvent, MmsAttributes, SpanKind } from '../tracing';
    12→    12→import { DatabaseError, TimeoutError } from '../errors';
    13→    13→import { logger } from '../logging/logger';
    14→    14→
    15→    15→/**
    16→    16→ * Transaction options for controlling behavior
    17→    17→ */
    18→    18→export interface TransactionOptions {
    19→    19→  /** Maximum time to wait for transaction completion (ms) */
    20→    20→  timeoutMs?: number;
    21→    21→  /** Isolation level for the transaction */
    22→    22→  isolationLevel?: 'read_uncommitted' | 'read_committed' | 'repeatable_read' | 'serializable';
    23→    23→  /** Whether to trace the transaction */
    24→    24→  traceEnabled?: boolean;
    25→    25→  /** Custom operation name for tracing */
    26→    26→  operationName?: string;
    27→    27→}
    28→    28→
    29→    29→const DEFAULT_OPTIONS: Required<TransactionOptions> = {
    30→    30→  timeoutMs: 30000, // 30 seconds
    31→    31→  isolationLevel: 'read_committed',
    32→    32→  traceEnabled: true,
    33→    33→  operationName: 'transaction',
    34→    34→};
    35→    35→
    36→    36→/**
    37→    37→ * Transaction result with metadata
    38→    38→ */
    39→    39→export interface TransactionResult<T> {
    40→    40→  data: T;
    41→    41→  durationMs: number;
    42→    42→  rowsAffected?: number;
    43→    43→}
    44→    44→
    45→    45→/**
    46→    46→ * Execute a function within a traced database transaction
    47→    47→ *
    48→    48→ * Features:
    49→    49→ * - Automatic commit on success
    50→    50→ * - Automatic rollback on error
    51→    51→ * - Timeout protection
    52→    52→ * - OpenTelemetry tracing integration
    53→    53→ * - Structured logging
    54→    54→ *
    55→    55→ * @example
    56→    56→ * ```typescript
    57→    57→ * const result = await tracedTransaction(
    58→    58→ *   async (tx) => {
    59→    59→ *     await tx.insert(trains).values(trainData);
    60→    60→ *     await tx.insert(pmSchedule).values(scheduleData);
    61→    61→ *     return { trainId: trainData.id };
    62→    62→ *   },
    63→    63→ *   { operationName: 'createTrainWithSchedule', timeoutMs: 10000 }
    64→    64→ * );
    65→    65→ * ```
    66→    66→ */
    67→    67→export async function tracedTransaction<T>(
    68→    68→  fn: (tx: Transaction) => Promise<T>,
    69→    69→  options?: TransactionOptions
    70→    70→): Promise<TransactionResult<T>> {
    71→    71→  const opts = { ...DEFAULT_OPTIONS, ...options };
    72→    72→
    73→    73→  if (!opts.traceEnabled) {
    74→    74→    return executeTransaction(fn, opts);
    75→    75→  }
    76→    76→
    77→    77→  return withSpan(
    78→    78→    `db.${opts.operationName}`,
    79→    79→    async (span) => {
    80→    80→      span.setAttribute(MmsAttributes.DB_OPERATION, 'transaction');
    81→    81→      span.setAttribute('db.system', 'postgresql');
    82→    82→
    83→    83→      addSpanEvent('transaction.begin', {
    84→    84→        'db.transaction.isolation_level': opts.isolationLevel,
    85→    85→        'db.transaction.timeout_ms': opts.timeoutMs,
    86→    86→      });
    87→    87→
    88→    88→      try {
    89→    89→        const result = await executeTransaction(fn, opts);
    90→    90→
    91→    91→        addSpanEvent('transaction.commit', {
    92→    92→          'db.transaction.duration_ms': result.durationMs,
    93→    93→          ...(result.rowsAffected !== undefined && {
    94→    94→            'db.transaction.rows_affected': result.rowsAffected,
    95→    95→          }),
    96→    96→        });
    97→    97→
    98→    98→        span.setAttribute(MmsAttributes.DB_ROWS_AFFECTED, result.rowsAffected ?? 0);
    99→    99→
   100→   100→        return result;
   101→   101→      } catch (error) {
   102→   102→        addSpanEvent('transaction.rollback', {
   103→   103→          'db.transaction.error': error instanceof Error ? error.message : String(error),
   104→   104→        });
   105→   105→        throw error;
   106→   106→      }
   107→   107→    },
   108→   108→    { kind: SpanKind.CLIENT }
   109→   109→  );
   110→   110→}
   111→   111→
   112→   112→/**
   113→   113→ * Execute transaction without tracing (internal)
   114→   114→ */
   115→   115→async function executeTransaction<T>(
   116→   116→  fn: (tx: Transaction) => Promise<T>,
   117→   117→  opts: Required<TransactionOptions>
   118→   118→): Promise<TransactionResult<T>> {
   119→   119→  const startTime = Date.now();
   120→   120→
   121→   121→  // Create timeout promise
   122→   122→  const timeoutPromise = new Promise<never>((_, reject) => {
   123→   123→    setTimeout(() => {
   124→   124→      reject(
   125→   125→        new TimeoutError(`Transaction timed out after ${opts.timeoutMs}ms`, {
   126→   126→          operation: opts.operationName,
   127→   127→          timeoutMs: opts.timeoutMs,
   128→   128→        })
   129→   129→      );
   130→   130→    }, opts.timeoutMs);
   131→   131→  });
   132→   132→
   133→   133→  try {
   134→   134→    // Race between transaction and timeout
   135→   135→    const data = await Promise.race([
   136→   136→      db.transaction(async (tx) => fn(tx)),
   137→   137→      timeoutPromise,
   138→   138→    ]);
   139→   139→
   140→   140→    return {
   141→   141→      data,
   142→   142→      durationMs: Date.now() - startTime,
   143→   143→    };
   144→   144→  } catch (error) {
   145→   145→    const durationMs = Date.now() - startTime;
   146→   146→
   147→   147→    // Enhance error with context
   148→   148→    if (error instanceof TimeoutError) {
   149→   149→      throw error;
   150→   150→    }
   151→   151→
   152→   152→    if (error instanceof Error) {
   153→   153→      logger.error(
   154→   154→        {
   155→   155→          operation: opts.operationName,
   156→   156→          durationMs,
   157→   157→          error: error.message,
   158→   158→        },
   159→   159→        'Transaction failed'
   160→   160→      );
   161→   161→
   162→   162→      throw new DatabaseError(`Transaction failed: ${error.message}`, {
   163→   163→        operation: opts.operationName,
   164→   164→        durationMs,
   165→   165→        originalError: error.name,
   166→   166→      });
   167→   167→    }
   168→   168→
   169→   169→    throw error;
   170→   170→  }
   171→   171→}
   172→   172→
   173→   173→/**
   174→   174→ * Simple transaction wrapper (non-traced)
   175→   175→ *
   176→   176→ * Use this for simple operations where tracing overhead is unnecessary.
   177→   177→ */
   178→   178→export async function simpleTransaction<T>(
   179→   179→  fn: (tx: Transaction) => Promise<T>
   180→   180→): Promise<T> {
   181→   181→  return db.transaction(async (tx) => fn(tx));
   182→   182→}
   183→   183→
   184→   184→/**
   185→   185→ * Execute multiple operations in a single transaction with individual error handling
   186→   186→ *
   187→   187→ * Useful for batch operations where you want to collect errors but continue processing.
   188→   188→ * The transaction only commits if all operations succeed.
   189→   189→ *
   190→   190→ * @example
   191→   191→ * ```typescript
   192→   192→ * const results = await batchTransaction([
   193→   193→ *   (tx) => tx.insert(trains).values(train1),
   194→   194→ *   (tx) => tx.insert(trains).values(train2),
   195→   195→ *   (tx) => tx.insert(trains).values(train3),
   196→   196→ * ]);
   197→   197→ * // results contains success/error for each operation
   198→   198→ * ```
   199→   199→ */
   200→   200→export interface BatchResult<T> {
   201→   201→  index: number;
   202→   202→  success: boolean;
   203→   203→  data?: T;
   204→   204→  error?: Error;
   205→   205→}
   206→   206→
   207→   207→export async function batchTransaction<T>(
   208→   208→  operations: Array<(tx: Transaction) => Promise<T>>,
   209→   209→  options?: TransactionOptions
   210→   210→): Promise<BatchResult<T>[]> {
   211→   211→  const opts = { ...DEFAULT_OPTIONS, ...options, operationName: options?.operationName ?? 'batch' };
   212→   212→
   213→   213→  const result = await tracedTransaction<BatchResult<T>[]>(
   214→   214→    async (tx) => {
   215→   215→      const results: BatchResult<T>[] = [];
   216→   216→
   217→   217→      for (let i = 0; i < operations.length; i++) {
   218→   218→        const operation = operations[i];
   219→   219→        if (!operation) continue;
   220→   220→
   221→   221→        try {
   222→   222→          const data = await operation(tx);
   223→   223→          results.push({ index: i, success: true, data });
   224→   224→        } catch (error) {
   225→   225→          // In a strict batch, any error should fail the whole transaction
   226→   226→          // Re-throw to trigger rollback
   227→   227→          results.push({
   228→   228→            index: i,
   229→   229→            success: false,
   230→   230→            error: error instanceof Error ? error : new Error(String(error)),
   231→   231→          });
   232→   232→          throw error;
   233→   233→        }
   234→   234→      }
   235→   235→
   236→   236→      return results;
   237→   237→    },
   238→   238→    opts
   239→   239→  );
   240→   240→
   241→   241→  return result.data;
   242→   242→}
   243→   243→
   244→   244→/**
   245→   245→ * Execute a read-only query (no transaction needed, but with tracing)
   246→   246→ */
   247→   247→export async function tracedQuery<T>(
   248→   248→  operationName: string,
   249→   249→  fn: (database: Database) => Promise<T>
   250→   250→): Promise<T> {
   251→   251→  return withSpan(
   252→   252→    `db.query.${operationName}`,
   253→   253→    async (span) => {
   254→   254→      span.setAttribute(MmsAttributes.DB_OPERATION, 'query');
   255→   255→      span.setAttribute('db.system', 'postgresql');
   256→   256→
   257→   257→      const startTime = Date.now();
   258→   258→      const result = await fn(db);
   259→   259→      const durationMs = Date.now() - startTime;
   260→   260→
   261→   261→      span.setAttribute('db.query.duration_ms', durationMs);
   262→   262→
   263→   263→      return result;
   264→   264→    },
   265→   265→    { kind: SpanKind.CLIENT }
   266→   266→  );
   267→   267→}
   268→   268→
   269→   269→/**
   270→   270→ * Re-export Transaction type for convenience
   271→   271→ */
   272→   272→export type { Transaction, Database };
   273→   273→
