   208→/**
   209→ * Validate date range (start <= end)
   210→ */
   211→export function validateDateRange(range: DateRange): { valid: boolean; message?: string } {
   212→  if (!isValidDateString(range.startDate)) {
   213→    return { valid: false, message: 'Start date must be in YYYY-MM-DD format' };
   214→  }
   215→  if (!isValidDateString(range.endDate)) {
   216→    return { valid: false, message: 'End date must be in YYYY-MM-DD format' };
   217→  }
   218→  if (new Date(range.startDate) > new Date(range.endDate)) {
   219→    return { valid: false, message: 'Start date must be before or equal to end date' };
   220→  }
   221→  return { valid: true };
   222→}
