   187→      test('should calculate window for 12-month interval', () => {
   188→        const lastPmDate = new Date('2025-01-15');
   189→        const window = calculateComplianceWindow({
   190→          lastPmDate,
   191→          intervalMonths: 12,
   192→        });
   193→
   194→        expect(window.isValid).toBe(true);
   195→
   196→        // Target date should be 12 months after last PM
   197→        const expectedTarget = addMonths(lastPmDate, 12);
   198→        expect(window.targetDate.getTime()).toBe(expectedTarget.getTime());
   199→
   200→        // Window should be ±10% of 12 months (±36 days)
   201→        const toleranceDays = Math.floor(12 * 30 * COMPLIANCE_TOLERANCE_PCT);
   202→        expect(toleranceDays).toBe(36);
   203→
   204→        const expectedStart = addDays(expectedTarget, -toleranceDays);
   205→        const expectedEnd = addDays(expectedTarget, toleranceDays);
